#[derive(Debug)]
struct CollectionStore {
    records: Vec<CollectionRecord>,
    next_id: u64,
    updated_at: u64,
}

impl CollectionStore {
    fn new() -> Self {
        Self {
            records: Vec::new(),
            next_id: 1,
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(
        collections: Vec<crate::persistence::CollectionRecord>,
        items: Vec<crate::persistence::CollectionItemRecord>,
    ) -> Self {
        let mut next_id = 1;
        let mut updated_at = unix_timestamp();
        let mut records = collections
            .into_iter()
            .map(|record| {
                if let Some(number) = record
                    .id
                    .strip_prefix("col-")
                    .and_then(|value| value.parse::<u64>().ok())
                {
                    next_id = next_id.max(number.saturating_add(1));
                }
                let created_at = u64::try_from(record.created_at).unwrap_or(0);
                let record_updated_at = u64::try_from(record.updated_at).unwrap_or(created_at);
                updated_at = updated_at.max(record_updated_at);
                CollectionRecord {
                    id: record.id,
                    name: record.name,
                    description: record.description,
                    items: Vec::new(),
                    created_at,
                    updated_at: record_updated_at,
                }
            })
            .collect::<Vec<_>>();
        let mut items = items;
        items.sort_by_key(|item| (item.collection_id.clone(), item.position, item.added_at));
        for item in items {
            let Some(collection) = records
                .iter_mut()
                .find(|record| record.id == item.collection_id)
            else {
                continue;
            };
            collection.items.push(CollectionItem {
                id: item.id,
                content_id: item.content_id,
                artist: item.artist,
                title: item.title,
                kind: item.kind,
                added_at: u64::try_from(item.added_at).unwrap_or(0),
            });
        }
        Self {
            records,
            next_id,
            updated_at,
        }
    }

    fn create(&mut self, name: String, description: String) -> CollectionRecord {
        let now = unix_timestamp();
        let id = format!("col-{}", self.next_id);
        self.next_id += 1;
        let record = CollectionRecord {
            id,
            name,
            description,
            items: Vec::new(),
            created_at: now,
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        record
    }

    fn get(&self, id: &str) -> Option<CollectionRecord> {
        self.records.iter().find(|r| r.id == id).cloned()
    }

    fn update(&mut self, id: &str, name: String, description: String) -> Option<CollectionRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == id)?;
        record.name = name;
        record.description = description;
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn delete(&mut self, id: &str) -> bool {
        if let Some(pos) = self.records.iter().position(|r| r.id == id) {
            self.records.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn add_item(&mut self, collection_id: &str, item: CollectionItem) -> Option<CollectionRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == collection_id)?;
        record.items.push(item);
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn update_item(
        &mut self,
        item_id: &str,
        artist: Option<String>,
        title: Option<String>,
        kind: Option<String>,
    ) -> Option<CollectionItem> {
        let now = unix_timestamp();
        for record in &mut self.records {
            if let Some(item) = record.items.iter_mut().find(|item| item.id == item_id) {
                if let Some(artist) = artist {
                    item.artist = artist;
                }
                if let Some(title) = title {
                    item.title = title;
                }
                if let Some(kind) = kind {
                    item.kind = kind;
                }
                record.updated_at = now;
                self.updated_at = now;
                return Some(item.clone());
            }
        }
        None
    }

    fn remove_item(&mut self, item_id: &str) -> Option<CollectionItem> {
        let now = unix_timestamp();
        for record in &mut self.records {
            if let Some(pos) = record.items.iter().position(|item| item.id == item_id) {
                let item = record.items.remove(pos);
                record.updated_at = now;
                self.updated_at = now;
                return Some(item);
            }
        }
        None
    }

    fn collection_id_for_item(&self, item_id: &str) -> Option<String> {
        self.records
            .iter()
            .find(|record| record.items.iter().any(|item| item.id == item_id))
            .map(|record| record.id.clone())
    }

    fn reorder_items(&mut self, collection_id: &str, body: &str) -> Option<CollectionRecord> {
        let now = unix_timestamp();
        let record = self
            .records
            .iter_mut()
            .find(|record| record.id == collection_id)?;
        let payload = serde_json::from_str::<serde_json::Value>(body).ok();
        let ids = payload
            .as_ref()
            .and_then(|value| {
                value
                    .get("item_ids")
                    .or_else(|| value.get("itemIds"))
                    .or_else(|| value.get("items"))
            })
            .and_then(serde_json::Value::as_array)
            .map(|array| {
                array
                    .iter()
                    .filter_map(serde_json::Value::as_str)
                    .map(str::to_owned)
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        if !ids.is_empty() {
            let mut ordered = Vec::new();
            for id in &ids {
                if let Some(pos) = record.items.iter().position(|item| item.id == *id) {
                    ordered.push(record.items.remove(pos));
                }
            }
            ordered.append(&mut record.items);
            record.items = ordered;
        }
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    #[allow(dead_code)]
    fn json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let filtered_count = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .map_or(true, |q| record.name.to_ascii_lowercase().contains(q))
            })
            .count();
        format!(
            "{{\"entries\":{},\"count\":{},\"filtered_count\":{},\"offset\":{},\"limit\":{},\"updated_at\":{}}}",
            self.json_array(query),
            self.records.len(),
            filtered_count,
            filter.offset,
            json_usize_option(filter.limit),
            self.updated_at
        )
    }

    fn json_array(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .map_or(true, |q| record.name.to_ascii_lowercase().contains(q))
            })
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(CollectionRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }
}

// Wishlist Models
#[derive(Clone, Debug)]
struct WishlistItem {
    id: String,
    artist: String,
    title: String,
    kind: String,
    added_at: u64,
}

impl WishlistItem {
    fn search_text(&self) -> String {
        match (self.artist.trim().is_empty(), self.title.trim().is_empty()) {
            (true, true) => String::new(),
            (true, false) => self.title.clone(),
            (false, true) => self.artist.clone(),
            (false, false) => format!("{} {}", self.artist, self.title),
        }
    }

    fn json(&self) -> String {
        let search_text = self.search_text();
        format!(
            "{{\"id\":\"{}\",\"artist\":\"{}\",\"title\":\"{}\",\"kind\":\"{}\",\"added_at\":{},\"searchText\":\"{}\",\"filter\":\"\",\"enabled\":true,\"autoDownload\":false,\"maxResults\":100,\"lastSearchedAt\":null,\"lastMatchCount\":0,\"totalSearchCount\":0,\"lastSearchId\":null}}",
            json_escape(&self.id),
            json_escape(&self.artist),
            json_escape(&self.title),
            json_escape(&self.kind),
            self.added_at,
            json_escape(&search_text)
        )
    }
}

#[derive(Clone, Debug)]
struct WishlistRecord {
    id: String,
    items: Vec<WishlistItem>,
    updated_at: u64,
}

#[derive(Debug)]
struct WishlistStore {
    records: Vec<WishlistRecord>,
    updated_at: u64,
}

impl WishlistStore {
    fn new() -> Self {
        Self {
            records: Vec::new(),
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(records: Vec<crate::persistence::WishlistItemRecord>) -> Self {
        let mut store = Self::new();
        let mut items = records
            .into_iter()
            .map(|record| WishlistItem {
                id: record.id,
                artist: record.artist,
                title: record.title,
                kind: record.kind,
                added_at: u64::try_from(record.added_at).unwrap_or(0),
            })
            .collect::<Vec<_>>();
        items.sort_by_key(|item| item.added_at);
        let updated_at = items
            .iter()
            .map(|item| item.added_at)
            .max()
            .unwrap_or_else(unix_timestamp);
        store.records.push(WishlistRecord {
            id: "default".to_owned(),
            items,
            updated_at,
        });
        store.updated_at = updated_at;
        store
    }

    fn get_or_create(&mut self) -> WishlistRecord {
        let now = unix_timestamp();
        if let Some(record) = self.records.iter_mut().find(|r| r.id == "default") {
            record.clone()
        } else {
            let record = WishlistRecord {
                id: "default".to_string(),
                items: Vec::new(),
                updated_at: now,
            };
            self.records.push(record.clone());
            self.updated_at = now;
            record
        }
    }

    fn add_item(&mut self, item: WishlistItem) -> Option<WishlistRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == "default")?;
        record.items.push(item);
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn remove_item(&mut self, item_id: &str) -> Option<WishlistRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == "default")?;
        if let Some(pos) = record.items.iter().position(|i| i.id == item_id) {
            record.items.remove(pos);
            record.updated_at = now;
            self.updated_at = now;
            Some(record.clone())
        } else {
            None
        }
    }

    fn update_item(
        &mut self,
        item_id: &str,
        artist: Option<String>,
        title: Option<String>,
        kind: Option<String>,
    ) -> Option<WishlistItem> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == "default")?;
        let item = record.items.iter_mut().find(|item| item.id == item_id)?;
        if let Some(artist) = artist {
            item.artist = artist;
        }
        if let Some(title) = title {
            item.title = title;
        }
        if let Some(kind) = kind {
            item.kind = kind;
        }
        record.updated_at = now;
        self.updated_at = now;
        Some(item.clone())
    }

    fn json_array(&mut self) -> String {
        let record = self.get_or_create();
        let items = record
            .items
            .iter()
            .map(WishlistItem::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", items)
    }

    fn search_terms(&self) -> Vec<String> {
        self.records
            .iter()
            .flat_map(|record| record.items.iter())
            .map(|item| {
                if item.title.is_empty() {
                    item.artist.clone()
                } else if item.artist.is_empty() {
                    item.title.clone()
                } else {
                    format!("{} {}", item.artist, item.title)
                }
            })
            .filter(|term| !term.trim().is_empty())
            .collect()
    }

    fn get_item(&self, item_id: &str) -> Option<WishlistItem> {
        self.records
            .iter()
            .flat_map(|record| record.items.iter())
            .find(|item| item.id == item_id)
            .cloned()
    }
}

