impl ShareGroupStore {
    fn new() -> Self {
        Self {
            records: Vec::new(),
            next_id: 1,
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(
        groups: Vec<crate::persistence::ShareGroupRecord>,
        members: Vec<crate::persistence::ShareGroupMemberRecord>,
    ) -> Self {
        let mut store = Self::new();
        let mut max_id = 0_u64;
        store.records = groups
            .into_iter()
            .map(|record| {
                if let Some(value) = record
                    .id
                    .strip_prefix("sg-")
                    .and_then(|value| value.parse::<u64>().ok())
                {
                    max_id = max_id.max(value);
                }
                ShareGroupRecord {
                    id: record.id,
                    name: record.name,
                    description: record.description,
                    members: Vec::new(),
                    created_at: u64::try_from(record.created_at).unwrap_or_default(),
                    updated_at: u64::try_from(record.updated_at).unwrap_or_default(),
                }
            })
            .collect();
        for member in members {
            if let Some(group) = store
                .records
                .iter_mut()
                .find(|record| record.id == member.group_id)
            {
                group.members.push(ShareGroupMember {
                    username: member.username,
                    added_at: u64::try_from(member.added_at).unwrap_or_default(),
                });
            }
        }
        for group in &mut store.records {
            group.members.sort_by(|left, right| {
                left.username
                    .cmp(&right.username)
                    .then(left.added_at.cmp(&right.added_at))
            });
        }
        store.next_id = max_id.saturating_add(1).max(1);
        store.updated_at = store
            .records
            .iter()
            .map(|record| record.updated_at)
            .max()
            .unwrap_or_else(unix_timestamp);
        store
    }

    fn create(&mut self, name: String, description: String) -> ShareGroupRecord {
        let now = unix_timestamp();
        let id = format!("sg-{}", self.next_id);
        self.next_id += 1;
        let record = ShareGroupRecord {
            id,
            name,
            description,
            members: Vec::new(),
            created_at: now,
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        record
    }

    fn get(&self, id: &str) -> Option<ShareGroupRecord> {
        self.records.iter().find(|r| r.id == id).cloned()
    }

    fn update(&mut self, id: &str, name: String, description: String) -> Option<ShareGroupRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == id)?;
        record.name = name;
        record.description = description;
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn delete(&mut self, id: &str) -> bool {
        if let Some(pos) = self.records.iter().position(|r| r.id == id) {
            self.records.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn add_member(&mut self, group_id: &str, username: String) -> Option<ShareGroupRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == group_id)?;
        if !record.members.iter().any(|m| m.username == username) {
            record.members.push(ShareGroupMember {
                username,
                added_at: now,
            });
            record.updated_at = now;
            self.updated_at = now;
        }
        Some(record.clone())
    }

    fn remove_member(&mut self, group_id: &str, username: &str) -> Option<ShareGroupRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == group_id)?;
        if let Some(pos) = record.members.iter().position(|m| m.username == username) {
            record.members.remove(pos);
            record.updated_at = now;
            self.updated_at = now;
            Some(record.clone())
        } else {
            None
        }
    }

    fn user_group_json(&self, username: &str) -> String {
        let groups = self
            .records
            .iter()
            .filter_map(|record| {
                let member = record
                    .members
                    .iter()
                    .find(|member| member.username == username)?;
                Some(serde_json::json!({
                    "id": record.id,
                    "name": record.name,
                    "description": record.description,
                    "added_at": member.added_at,
                }))
            })
            .collect::<Vec<_>>();
        let primary_group = groups
            .first()
            .and_then(|group| group.get("name"))
            .and_then(serde_json::Value::as_str)
            .unwrap_or("default");
        let primary_group_id = groups.first().and_then(|group| group.get("id")).cloned();
        serde_json::json!({
            "username": username,
            "group": primary_group,
            "group_id": primary_group_id,
            "groups": groups,
            "groupCount": groups.len(),
        })
        .to_string()
    }

    #[allow(dead_code)]
    fn json(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let filtered_count = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .map_or(true, |q| record.name.to_ascii_lowercase().contains(q))
            })
            .count();
        format!(
            "{{\"entries\":{},\"count\":{},\"filtered_count\":{},\"offset\":{},\"limit\":{},\"updated_at\":{}}}",
            self.json_array(query),
            self.records.len(),
            filtered_count,
            filter.offset,
            json_usize_option(filter.limit),
            self.updated_at
        )
    }

    fn json_array(&self, query: Option<&str>) -> String {
        let filter = RecordListFilter::from_query(query);
        let records = self
            .records
            .iter()
            .filter(|record| {
                filter
                    .q
                    .as_deref()
                    .map_or(true, |q| record.name.to_ascii_lowercase().contains(q))
            })
            .skip(filter.offset)
            .take(filter.limit.unwrap_or(usize::MAX))
            .map(ShareGroupRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{}]", records)
    }
}

