#[derive(Debug)]
struct UserNoteStore {
    records: Vec<UserNoteRecord>,
    next_id: u64,
    updated_at: u64,
}

impl UserNoteStore {
    fn new() -> Self {
        Self {
            records: Vec::new(),
            next_id: 1,
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(records: Vec<crate::persistence::UserNoteRecord>) -> Self {
        let mut next_id = 1;
        let mut updated_at = unix_timestamp();
        let records = records
            .into_iter()
            .map(|record| {
                if let Some(number) = record
                    .id
                    .strip_prefix("note-")
                    .and_then(|value| value.parse::<u64>().ok())
                {
                    next_id = next_id.max(number.saturating_add(1));
                }
                let created_at = u64::try_from(record.created_at).unwrap_or(0);
                let record_updated_at = u64::try_from(record.updated_at).unwrap_or(created_at);
                updated_at = updated_at.max(record_updated_at);
                UserNoteRecord {
                    id: record.id,
                    username: record.username,
                    note: record.note,
                    created_at,
                    updated_at: record_updated_at,
                }
            })
            .collect();
        Self {
            records,
            next_id,
            updated_at,
        }
    }

    fn create(&mut self, username: String, note: String) -> UserNoteRecord {
        let now = unix_timestamp();
        let id = format!("note-{}", self.next_id);
        self.next_id += 1;
        let record = UserNoteRecord {
            id,
            username,
            note,
            created_at: now,
            updated_at: now,
        };
        self.records.push(record.clone());
        self.updated_at = now;
        record
    }

    fn get(&self, id: &str) -> Option<UserNoteRecord> {
        self.records.iter().find(|r| r.id == id).cloned()
    }

    fn update(&mut self, id: &str, note: String) -> Option<UserNoteRecord> {
        let now = unix_timestamp();
        let record = self.records.iter_mut().find(|r| r.id == id)?;
        record.note = note;
        record.updated_at = now;
        self.updated_at = now;
        Some(record.clone())
    }

    fn delete(&mut self, id: &str) -> bool {
        if let Some(pos) = self.records.iter().position(|r| r.id == id) {
            self.records.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn json(&self, _query: Option<&str>) -> String {
        let records = self
            .records
            .iter()
            .map(UserNoteRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"entries\":[{}],\"count\":{},\"updated_at\":{}}}",
            records,
            self.records.len(),
            self.updated_at
        )
    }
}

