#[derive(Debug)]
struct InterestStore {
    liked: Vec<InterestRecord>,
    hated: Vec<InterestRecord>,
    next_id: u64,
    updated_at: u64,
}

impl InterestStore {
    fn new() -> Self {
        Self {
            liked: Vec::new(),
            hated: Vec::new(),
            next_id: 1,
            updated_at: unix_timestamp(),
        }
    }

    fn from_persisted(records: Vec<crate::persistence::InterestRecord>) -> Self {
        let mut store = Self::new();
        store.liked.clear();
        store.hated.clear();
        for record in records {
            if let Some(number) = record
                .id
                .split_once('-')
                .and_then(|(_, value)| value.parse::<u64>().ok())
            {
                store.next_id = store.next_id.max(number.saturating_add(1));
            }
            let created_at = u64::try_from(record.created_at).unwrap_or(0);
            store.updated_at = store.updated_at.max(created_at);
            let record = InterestRecord {
                id: record.id,
                name: record.name,
                kind: record.kind,
                created_at,
            };
            if record.kind == "hated" {
                store.hated.push(record);
            } else {
                store.liked.push(record);
            }
        }
        store
    }

    fn add_liked(&mut self, name: String) -> InterestRecord {
        let now = unix_timestamp();
        let id = format!("liked-{}", self.next_id);
        self.next_id += 1;
        let record = InterestRecord {
            id,
            name,
            kind: "liked".to_string(),
            created_at: now,
        };
        self.liked.push(record.clone());
        self.updated_at = now;
        record
    }

    fn add_hated(&mut self, name: String) -> InterestRecord {
        let now = unix_timestamp();
        let id = format!("hated-{}", self.next_id);
        self.next_id += 1;
        let record = InterestRecord {
            id,
            name,
            kind: "hated".to_string(),
            created_at: now,
        };
        self.hated.push(record.clone());
        self.updated_at = now;
        record
    }

    fn remove_liked(&mut self, id: &str) -> bool {
        if let Some(pos) = self.liked.iter().position(|r| r.id == id) {
            self.liked.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn remove_hated(&mut self, id: &str) -> bool {
        if let Some(pos) = self.hated.iter().position(|r| r.id == id) {
            self.hated.remove(pos);
            self.updated_at = unix_timestamp();
            true
        } else {
            false
        }
    }

    fn json_liked(&self) -> String {
        let records = self
            .liked
            .iter()
            .map(InterestRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"entries\":[{}],\"count\":{},\"kind\":\"liked\",\"updated_at\":{}}}",
            records,
            self.liked.len(),
            self.updated_at
        )
    }

    fn json_hated(&self) -> String {
        let records = self
            .hated
            .iter()
            .map(InterestRecord::json)
            .collect::<Vec<_>>()
            .join(",");
        format!(
            "{{\"entries\":[{}],\"count\":{},\"kind\":\"hated\",\"updated_at\":{}}}",
            records,
            self.hated.len(),
            self.updated_at
        )
    }

    fn user_interests_json(&self, username: &str) -> String {
        let liked = self
            .liked
            .iter()
            .map(InterestRecord::json)
            .collect::<Vec<_>>();
        let hated = self
            .hated
            .iter()
            .map(InterestRecord::json)
            .collect::<Vec<_>>();
        format!(
            "{{\"username\":\"{}\",\"liked\":[{}],\"hated\":[{}],\"interests\":[{}],\"count\":{},\"updated_at\":{}}}",
            json_escape(username),
            liked.join(","),
            hated.join(","),
            liked.join(","),
            self.liked.len() + self.hated.len(),
            self.updated_at
        )
    }

    fn recommendations_json(&self, field: &str) -> String {
        let recommendations = self
            .liked
            .iter()
            .enumerate()
            .map(|(index, interest)| {
                format!(
                    "{{\"id\":\"rec-{}\",\"interest\":\"{}\",\"query\":\"{}\",\"score\":{},\"source\":\"liked-interest\"}}",
                    index + 1,
                    json_escape(&interest.name),
                    json_escape(&interest.name),
                    100_u64.saturating_sub(index as u64)
                )
            })
            .collect::<Vec<_>>();
        format!(
            "{{\"{}\":[{}],\"count\":{},\"updated_at\":{}}}",
            field,
            recommendations.join(","),
            recommendations.len(),
            self.updated_at
        )
    }

    fn item_recommendations_json(&self, item_id: &str) -> String {
        let recommendations = self
            .liked
            .iter()
            .enumerate()
            .map(|(index, interest)| {
                format!(
                    "{{\"id\":\"{}-rec-{}\",\"item_id\":\"{}\",\"interest\":\"{}\",\"score\":{},\"source\":\"liked-interest\"}}",
                    json_escape(item_id),
                    index + 1,
                    json_escape(item_id),
                    json_escape(&interest.name),
                    100_u64.saturating_sub(index as u64)
                )
            })
            .collect::<Vec<_>>();
        format!(
            "{{\"item_id\":\"{}\",\"recommendations\":[{}],\"count\":{},\"updated_at\":{}}}",
            json_escape(item_id),
            recommendations.join(","),
            recommendations.len(),
            self.updated_at
        )
    }
}

