fn extract_json_u32_field(body: &str, field: &str) -> Option<u32> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()?
        .get(field)?
        .as_u64()
        .and_then(|value| u32::try_from(value).ok())
}

fn extract_json_bool_field(body: &str, field: &str) -> Option<bool> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()?
        .get(field)?
        .as_bool()
}

fn extract_json_u64_field(body: &str, field: &str) -> Option<u64> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()?
        .get(field)?
        .as_u64()
}

fn extract_json_i32_field(body: &str, field: &str) -> Option<i32> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()?
        .get(field)?
        .as_i64()
        .and_then(|value| i32::try_from(value).ok())
}

fn rate_limit_user_key(authorization: Option<&str>, cookie: Option<&str>) -> String {
    use sha2::{Digest, Sha256};

    let token = authorization
        .and_then(|value| {
            value
                .strip_prefix("Bearer ")
                .or_else(|| value.strip_prefix("ApiKey "))
        })
        .or_else(|| {
            cookie?.split(';').find_map(|part| {
                let (name, value) = part.trim().split_once('=')?;
                (name == "slskr.session").then_some(value)
            })
        })
        .unwrap_or("authenticated");
    let digest = Sha256::digest(token.as_bytes());
    format!("auth:{}", hex::encode(&digest[..16]))
}

fn rate_limit_remote_addr(
    config: &AppConfig,
    remote_addr: Option<SocketAddr>,
    headers: &http_server::HttpHeaders,
) -> Option<SocketAddr> {
    let remote_addr = remote_addr?;
    if !config
        .trusted_proxy_cidrs
        .iter()
        .any(|cidr| cidr.contains(remote_addr.ip()))
    {
        return Some(remote_addr);
    }

    forwarded_client_ip(headers)
        .map(|ip| SocketAddr::new(ip, 0))
        .or(Some(remote_addr))
}

fn forwarded_client_ip(headers: &http_server::HttpHeaders) -> Option<IpAddr> {
    headers
        .forwarded
        .as_deref()
        .and_then(forwarded_header_client_ip)
        .or_else(|| {
            headers
                .x_forwarded_for
                .as_deref()
                .and_then(x_forwarded_for_client_ip)
        })
}

fn x_forwarded_for_client_ip(value: &str) -> Option<IpAddr> {
    value.split(',').find_map(parse_forwarded_ip_token)
}

fn forwarded_header_client_ip(value: &str) -> Option<IpAddr> {
    value
        .split(',')
        .flat_map(|entry| entry.split(';'))
        .find_map(|part| {
            let (name, value) = part.trim().split_once('=')?;
            name.trim()
                .eq_ignore_ascii_case("for")
                .then_some(value)
                .and_then(parse_forwarded_ip_token)
        })
}

fn parse_forwarded_ip_token(value: &str) -> Option<IpAddr> {
    let value = value.trim().trim_matches('"');
    if value.eq_ignore_ascii_case("unknown") || value.starts_with('_') {
        return None;
    }
    let without_brackets = value
        .strip_prefix('[')
        .and_then(|value| value.split_once(']').map(|(ip, _)| ip))
        .unwrap_or(value);
    if let Ok(ip) = without_brackets.parse::<IpAddr>() {
        return Some(ip);
    }
    let host_part = without_brackets
        .rsplit_once(':')
        .filter(|(host, port)| !host.contains(':') && port.parse::<u16>().is_ok())
        .map(|(host, _)| host)
        .unwrap_or(without_brackets);
    host_part.parse::<IpAddr>().ok()
}

fn websocket_auth_protocol(protocol_header: Option<&str>) -> Option<&str> {
    protocol_header?.split(',').map(str::trim).find(|protocol| {
        let Some(encoded) = protocol.strip_prefix(WEBSOCKET_AUTH_PROTOCOL_PREFIX) else {
            return false;
        };
        let token = percent_decode(encoded);
        !token.is_empty() && !token.contains('\r') && !token.contains('\n')
    })
}

fn websocket_protocol_authorization(protocol_header: Option<&str>) -> Option<String> {
    let protocol = websocket_auth_protocol(protocol_header)?;
    let token = percent_decode(protocol.strip_prefix(WEBSOCKET_AUTH_PROTOCOL_PREFIX)?);
    Some(format!("Bearer {token}"))
}

fn slskd_transfer_user_path<'a>(path: &'a str, direction: &str) -> Option<&'a str> {
    let prefix = format!("/api/transfers/{direction}/");
    path.strip_prefix(&prefix)
        .filter(|username| !username.is_empty() && !username.contains('/'))
}

fn slskd_transfer_file_path<'a>(path: &'a str, direction: &str) -> Option<(&'a str, u64)> {
    let prefix = format!("/api/transfers/{direction}/");
    let rest = path.strip_prefix(&prefix)?;
    let (username, tail) = rest.split_once('/')?;
    let id = tail.split_once('/').map_or(
        tail,
        |(id, suffix)| {
            if suffix == "position" {
                id
            } else {
                ""
            }
        },
    );
    if username.is_empty() || username.contains('/') || id.is_empty() {
        return None;
    }
    Some((username, id.parse().ok()?))
}

fn slskd_transfer_position_path(path: &str) -> Option<(&str, u64)> {
    slskd_transfer_file_path(path, "downloads").filter(|_| path.ends_with("/position"))
}

fn slskd_files_from_body(body: &str) -> Vec<serde_json::Value> {
    let Ok(payload) = serde_json::from_str::<serde_json::Value>(body) else {
        return Vec::new();
    };
    if let Some(files) = payload.get("files").and_then(serde_json::Value::as_array) {
        return files.clone();
    }
    if payload.get("filename").is_some() {
        return vec![payload];
    }
    payload.as_array().cloned().unwrap_or_default()
}

fn slskd_transfer_batch_id(body: &str) -> Option<String> {
    let payload = serde_json::from_str::<serde_json::Value>(body).ok()?;
    ["batchId", "batch_id", "id"]
        .iter()
        .find_map(|field| payload.get(field).and_then(serde_json::Value::as_str))
        .map(str::trim)
        .filter(|value| !value.is_empty() && uuid::Uuid::parse_str(value).is_ok())
        .map(str::to_owned)
}

fn slskd_enqueue_request(body: &str) -> Option<(String, Vec<serde_json::Value>)> {
    let payload = serde_json::from_str::<serde_json::Value>(body).ok()?;
    let username = payload.get("username")?.as_str()?.to_owned();
    let files = payload
        .get("files")
        .and_then(serde_json::Value::as_array)
        .cloned()
        .unwrap_or_default();
    (!files.is_empty()).then_some((username, files))
}

fn json_body_string(body: &str) -> Option<String> {
    serde_json::from_str::<serde_json::Value>(body)
        .ok()
        .and_then(|value| value.as_str().map(str::to_owned))
}

fn path_segment_after<'a>(path: &'a str, prefix: &str) -> Option<&'a str> {
    path.strip_prefix(prefix)
        .filter(|segment| !segment.is_empty() && !segment.contains('/'))
}

fn decoded_path_segment(segment: &str) -> String {
    percent_decode(segment)
}

async fn create_preview_stream_ticket(
    state: &AppState,
    family: &str,
    body: &str,
) -> Result<String, String> {
    let content_id = extract_json_string_field(body, "contentId")
        .or_else(|| extract_json_string_field(body, "content_id"))
        .or_else(|| extract_json_string_field(body, "id"));
    let filename = extract_json_string_field(body, "filename")
        .or_else(|| extract_json_string_field(body, "path"))
        .or_else(|| content_id.clone())
        .ok_or_else(|| "filename/contentId is required".to_owned())?;
    let peer_username = extract_json_string_field(body, "username")
        .or_else(|| extract_json_string_field(body, "peerUsername"))
        .or_else(|| extract_json_string_field(body, "peer_username"))
        .or_else(|| extract_json_string_field(body, "peerId"));
    let requested_size = extract_json_u64_field(body, "size").unwrap_or(0);
    let content_type = extract_json_string_field(body, "contentType")
        .or_else(|| extract_json_string_field(body, "content_type"))
        .unwrap_or_else(|| preview_stream_content_type(&filename).to_owned());

    let shares = state.shares.read().await;
    let transfers = state.transfers.read().await;
    let searches = state.searches.read().await;
    let share = shares.entries.iter().find(|entry| {
        let hash = stable_content_hash(&entry.filename, entry.size).to_string();
        entry.filename == filename
            || content_id.as_deref() == Some(entry.filename.as_str())
            || content_id.as_deref() == Some(hash.as_str())
    });
    let transfer = transfers.entries.iter().find(|entry| {
        entry.filename == filename
            || content_id
                .as_deref()
                .and_then(|id| id.strip_prefix("transfer-"))
                .and_then(|id| id.parse::<u64>().ok())
                == Some(entry.id)
    });
    let search_result = searches.records.iter().find_map(|record| {
        record.results.iter().find(|result| {
            result.filename == filename
                || content_id.as_deref() == Some(result.filename.as_str())
                || peer_username
                    .as_deref()
                    .is_some_and(|peer| result.peer_username.as_deref() == Some(peer))
        })
    });

    let resolved_filename = share
        .map(|entry| entry.filename.clone())
        .or_else(|| transfer.map(|entry| entry.filename.clone()))
        .or_else(|| search_result.map(|entry| entry.filename.clone()))
        .unwrap_or(filename);
    let resolved_size = share
        .map(|entry| entry.size)
        .or_else(|| transfer.and_then(|entry| entry.size))
        .or_else(|| search_result.map(|entry| entry.size))
        .unwrap_or(requested_size);
    let resolved_content_id = content_id
        .unwrap_or_else(|| stable_content_hash(&resolved_filename, resolved_size).to_string());
    let source = if share.is_some() {
        "local-share"
    } else if transfer.is_some() {
        "transfer"
    } else if search_result.is_some() && family == "mesh" {
        "mesh-preview"
    } else if search_result.is_some() {
        "peer-preview"
    } else if family == "mesh" {
        "mesh-unresolved"
    } else {
        "peer-unresolved"
    };
    drop(searches);
    drop(transfers);
    drop(shares);

    let mut tickets = state.stream_tickets.write().await;
    let (token, ticket) = tickets.issue(
        family,
        source,
        resolved_content_id,
        resolved_filename,
        peer_username,
        resolved_size,
        content_type,
        120,
    );
    drop(tickets);

    let body = serde_json::json!({
        "ticket": token,
        "streamUrl": format!("/api/v0/{family}-streams/{}", url_encode(&token)),
        "stream_url": format!("/api/v0/{family}-streams/{}", url_encode(&token)),
        "expiresInSeconds": 120,
        "contentType": ticket.content_type,
        "content_id": ticket.content_id,
        "filename": ticket.filename,
        "size": ticket.size,
        "source": ticket.source,
    })
    .to_string();
    Ok(body)
}

async fn open_preview_stream_ticket(state: &AppState, family: &str, token: &str) -> Option<String> {
    let mut tickets = state.stream_tickets.write().await;
    let ticket = tickets.get(token);
    drop(tickets);
    let ticket = ticket?;
    if ticket.family != family {
        return None;
    }
    Some(
        serde_json::json!({
            "ticket": token,
            "status": "available",
            "source": ticket.source,
            "content_id": ticket.content_id,
            "filename": ticket.filename,
            "peer_username": ticket.peer_username,
            "size": ticket.size,
            "contentType": ticket.content_type,
            "created_at": ticket.created_at,
            "expires_at": ticket.expires_at,
            "cacheControl": "no-store",
            "acceptRanges": "none",
        })
        .to_string(),
    )
}

fn preview_stream_content_type(path: &str) -> &'static str {
    match path
        .rsplit_once('.')
        .map(|(_, extension)| extension.to_ascii_lowercase())
    {
        Some(extension) if extension == "flac" => "audio/flac",
        Some(extension) if extension == "mp3" => "audio/mpeg",
        Some(extension) if extension == "ogg" || extension == "oga" => "audio/ogg",
        Some(extension) if extension == "opus" => "audio/ogg; codecs=opus",
        Some(extension) if extension == "wav" => "audio/wav",
        Some(extension) if extension == "m4a" || extension == "mp4" => "audio/mp4",
        _ => "application/octet-stream",
    }
}

fn native_compat_path(path: &str) -> bool {
    let path = path.to_ascii_lowercase();
    let prefixes = [
        "/api/slskdn",
        "/api/multisource",
        "/api/podcore",
        "/api/hashdb",
        "/api/streams",
        "/api/listening-party",
        "/api/mesh",
        "/api/jobs",
        "/api/library/items",
        "/api/virtualsoulfind",
        "/api/audio",
        "/api/mediacore",
        "/api/playback",
        "/api/traces",
        "/api/fairness",
        "/api/ranking",
        "/api/portforwarding",
        "/api/signals",
        "/api/backfill",
        "/api/discovery",
        "/api/security",
        "/api/pods",
        "/api/solid",
        "/api/federation",
    ];
    prefixes
        .iter()
        .any(|prefix| path == *prefix || path.starts_with(&format!("{prefix}/")))
}

async fn native_compat_response(method: &str, path: &str, state: &AppState) -> HttpResponse {
    let session = state.session.read().await;
    let shares = state.shares.read().await;
    let searches = state.searches.read().await;
    let transfers = state.transfers.read().await;
    let listeners = state.listeners.read().await;
    let users = state.users.read().await;
    let rooms = state.rooms.read().await;
    let events = state.events.read().await;
    let library = state.library.read().await;
    let now_playing = state.now_playing.read().await;
    let security = state.security.read().await;
    let mesh = state.mesh.read().await;
    let collections = state.collections.read().await;
    let wishlist = state.wishlist.read().await;

    let family = path
        .trim_start_matches("/api/")
        .split('/')
        .next()
        .unwrap_or("native");
    let status = if method == "POST" || method == "PUT" || method == "DELETE" {
        "accepted"
    } else if family == "security" && security.active_bans() > 0 {
        "guarded"
    } else if family == "playback" && !now_playing.records.is_empty() {
        "playing"
    } else if family == "mesh" && (!users.records.is_empty() || !mesh.capability_records.is_empty())
    {
        "ready"
    } else if family == "solid" && (!collections.records.is_empty()) {
        "local"
    } else if matches!(family, "fairness" | "ranking")
        && (!transfers.entries.is_empty()
            || !searches.records.is_empty()
            || !users.records.is_empty())
    {
        "ready"
    } else if family == "portforwarding"
        && (listeners.regular_bind.is_some() || listeners.obfuscated_bind.is_some())
    {
        "configured"
    } else if family == "portforwarding" {
        "disabled"
    } else if family == "federation"
        && (!mesh.capability_records.is_empty() || !users.records.is_empty())
    {
        "ready"
    } else if session.state == "connected"
        || !shares.entries.is_empty()
        || !searches.records.is_empty()
    {
        "local"
    } else {
        "empty"
    };
    let jobs = searches
        .records
        .iter()
        .map(|record| {
            serde_json::json!({
                "id": record.id,
                "token": record.token,
                "kind": "search",
                "status": record.status,
                "query": record.query,
            })
        })
        .chain(transfers.entries.iter().map(|entry| {
            serde_json::json!({
                "id": format!("transfer-{}", entry.id),
                "kind": "transfer",
                "status": entry.status,
                "filename": entry.filename,
                "username": entry.peer_username,
            })
        }))
        .collect::<Vec<_>>();
    let items = match family {
        "library" => library
            .records
            .iter()
            .map(|record| {
                serde_json::from_str::<serde_json::Value>(&record.json())
                    .unwrap_or_else(|_| serde_json::json!({ "id": record.id }))
            })
            .collect::<Vec<_>>(),
        "playback" => now_playing
            .records
            .iter()
            .map(|record| {
                serde_json::from_str::<serde_json::Value>(&record.json())
                    .unwrap_or_else(|_| serde_json::json!({}))
            })
            .collect::<Vec<_>>(),
        "security" => security
            .json_value()
            .get("bans")
            .and_then(serde_json::Value::as_array)
            .cloned()
            .unwrap_or_default(),
        "fairness" => users
            .records
            .iter()
            .map(|user| {
                let queued = transfers
                    .entries
                    .iter()
                    .filter(|entry| {
                        entry.peer_username.as_deref() == Some(user.username.as_str())
                            && matches!(entry.status.as_str(), "queued" | "in_progress" | "requested")
                    })
                    .count();
                serde_json::json!({
                    "username": user.username,
                    "watched": user.watched,
                    "status": user.status,
                    "averageSpeed": user.average_speed.unwrap_or(0),
                    "queuedTransfers": queued,
                    "score": user.average_speed.unwrap_or(0) as u64 + user.file_count.unwrap_or(0) as u64,
                })
            })
            .collect::<Vec<_>>(),
        "ranking" => {
            let mut rows = transfers
                .entries
                .iter()
                .map(|entry| {
                    serde_json::json!({
                        "id": format!("transfer-{}", entry.id),
                        "kind": "transfer",
                        "score": entry.bytes_transferred,
                        "filename": entry.filename,
                        "username": entry.peer_username,
                        "status": entry.status,
                    })
                })
                .chain(searches.records.iter().map(|record| {
                    serde_json::json!({
                        "id": record.id,
                        "kind": "search",
                        "score": record.results.len(),
                        "query": record.query,
                        "status": record.status,
                    })
                }))
                .collect::<Vec<_>>();
            rows.sort_by(|a, b| {
                b.get("score")
                    .and_then(serde_json::Value::as_u64)
                    .cmp(&a.get("score").and_then(serde_json::Value::as_u64))
            });
            rows
        }
        "portforwarding" => vec![serde_json::json!({
            "regularBind": listeners.regular_bind,
            "regularLocalAddr": listeners.regular_local_addr,
            "obfuscatedBind": listeners.obfuscated_bind,
            "obfuscatedLocalAddr": listeners.obfuscated_local_addr,
            "regularAccepts": listeners.regular_accepts,
            "obfuscatedAccepts": listeners.obfuscated_accepts,
            "errors": listeners.errors,
            "lastError": listeners.last_error,
            "updated_at": listeners.updated_at,
        })],
        "solid" => collections
            .records
            .iter()
            .map(|collection| {
                serde_json::json!({
                    "id": collection.id,
                    "name": collection.name,
                    "itemCount": collection.items.len(),
                    "updated_at": collection.updated_at,
                    "storage": "local-collection",
                })
            })
            .collect::<Vec<_>>(),
        "federation" => mesh
            .capability_records
            .iter()
            .map(|record| {
                serde_json::json!({
                    "username": record.username,
                    "issuedAt": record.issued_at_unix,
                    "expiresAt": record.expires_at_unix,
                    "features": record.features.clone(),
                    "endpoints": record.endpoints.clone(),
                    "source": "peer-capability",
                })
            })
            .chain(users.records.iter().filter(|user| user.watched).map(|user| {
                serde_json::json!({
                    "username": user.username,
                    "status": user.status,
                    "source": "watched-user",
                })
            }))
            .collect::<Vec<_>>(),
        "pods" | "podcore" | "listening-party" => rooms
            .records
            .iter()
            .map(|room| {
                serde_json::json!({
                    "id": room.name,
                    "name": room.name,
                    "joined": room.joined,
                    "messageCount": room.messages.len(),
                    "userCount": room.user_count,
                })
            })
            .collect::<Vec<_>>(),
        "hashdb" | "streams" | "audio" | "mediacore" => shares
            .entries
            .iter()
            .take(DEFAULT_LIST_LIMIT)
            .map(|entry| {
                serde_json::json!({
                    "filename": entry.filename,
                    "size": entry.size,
                    "extension": entry.extension,
                })
            })
            .collect::<Vec<_>>(),
        "discovery" | "signals" | "traces" => events
            .records
            .iter()
            .rev()
            .take(50)
            .map(|event| {
                serde_json::json!({
                    "id": event.id,
                    "kind": event.kind,
                    "resource": event.resource,
                    "created_at": event.created_at,
                })
            })
            .collect::<Vec<_>>(),
        _ => users
            .records
            .iter()
            .map(|user| {
                serde_json::json!({
                    "username": user.username,
                    "status": user.status,
                    "watched": user.watched,
                })
            })
            .collect::<Vec<_>>(),
    };
    let item_count = items.len();
    let job_count = jobs.len();
    let body = serde_json::json!({
        "path": path,
        "method": method,
        "family": family,
        "status": status,
        "enabled": true,
        "supported": true,
        "connected": session.state == "connected",
        "items": items,
        "itemCount": item_count,
        "jobs": jobs,
        "jobCount": job_count,
        "counts": {
            "connected": session.state == "connected",
            "shares": shares.entries.len(),
            "searches": searches.records.len(),
            "transfers": transfers.entries.len(),
            "activeTransfers": transfers.entries.iter().filter(|entry| matches!(entry.status.as_str(), "queued" | "in_progress" | "requested")).count(),
            "users": users.records.len(),
            "watchedUsers": users.records.iter().filter(|user| user.watched).count(),
            "rooms": rooms.records.len(),
            "joinedRooms": rooms.records.iter().filter(|room| room.joined).count(),
            "events": events.records.len(),
            "libraryItems": library.records.len(),
            "wishlistItems": wishlist.records.iter().map(|record| record.items.len()).sum::<usize>(),
            "securityBans": security.active_bans(),
            "meshCapabilities": mesh.capability_records.len(),
            "collections": collections.records.len(),
            "listenerAccepts": listeners.regular_accepts + listeners.obfuscated_accepts,
            "listenerErrors": listeners.errors,
        },
    })
    .to_string();

    drop(wishlist);
    drop(collections);
    drop(mesh);
    drop(security);
    drop(now_playing);
    drop(library);
    drop(events);
    drop(rooms);
    drop(users);
    drop(listeners);
    drop(transfers);
    drop(searches);
    drop(shares);
    drop(session);

    if method == "POST" {
        routing::accepted_response(body)
    } else {
        routing::ok_response(body)
    }
}

fn conversation_message_path(path: &str) -> Option<(&str, u64)> {
    let rest = path.strip_prefix("/api/conversations/")?;
    let (username, id) = rest.split_once('/')?;
    if username.is_empty() || username.contains('/') || id.contains('/') {
        return None;
    }
    Some((username, id.parse().ok()?))
}

fn conversation_messages_path(path: &str) -> Option<&str> {
    path.strip_prefix("/api/conversations/")?
        .strip_suffix("/messages")
        .filter(|username| !username.is_empty() && !username.contains('/'))
}

fn slskd_user_file_json(entry: &BrowseEntry) -> serde_json::Value {
    serde_json::json!({
        "filename": entry.filename,
        "size": entry.size,
        "code": 1,
        "extension": entry.extension,
        "attributeCount": 0,
        "attributes": [],
    })
}

fn slskd_share_file_json(entry: &FileEntry) -> serde_json::Value {
    serde_json::json!({
        "filename": entry.filename,
        "size": entry.size,
        "code": 1,
        "extension": entry.extension,
        "attributeCount": 0,
        "attributes": [],
    })
}

fn share_entry_matches_prefix(entry: &FileEntry, share_id: &str) -> bool {
    share_id.is_empty()
        || share_id == "shares"
        || entry.filename == share_id
        || entry
            .filename
            .strip_prefix(share_id)
            .is_some_and(|rest| rest.starts_with('/'))
}

fn slskd_share_directories_json(entries: &[FileEntry], share_id: Option<&str>) -> String {
    let filtered = entries
        .iter()
        .filter(|entry| {
            share_id.map_or(true, |share_id| share_entry_matches_prefix(entry, share_id))
        })
        .cloned()
        .collect::<Vec<_>>();
    let directories = group_share_entries(&filtered)
        .into_iter()
        .map(|(name, files)| {
            serde_json::json!({
                "name": name,
                "fileCount": files.len(),
                "files": files.iter().map(slskd_share_file_json).collect::<Vec<_>>(),
            })
        })
        .collect::<Vec<_>>();
    serde_json::Value::Array(directories).to_string()
}

fn slskd_user_directories_json(
    directory: &str,
    entries: &[BrowseEntry],
    query: Option<&str>,
) -> String {
    let filter = RecordListFilter::from_query(query);
    let files = entries
        .iter()
        .filter(|entry| virtual_folder(&entry.filename) == directory)
        .collect::<Vec<_>>();
    let file_count = files.len();
    let filtered_files = files
        .into_iter()
        .filter(|entry| {
            filter
                .q
                .as_deref()
                .map_or(true, |q| entry.filename.to_ascii_lowercase().contains(q))
        })
        .collect::<Vec<_>>();
    let filtered_file_count = filtered_files.len();
    let total_bytes = filtered_files.iter().map(|entry| entry.size).sum::<u64>();
    let files = filtered_files
        .into_iter()
        .skip(filter.offset)
        .take(filter.limit.unwrap_or(usize::MAX))
        .map(slskd_user_file_json)
        .collect::<Vec<_>>();
    serde_json::Value::Array(vec![serde_json::json!({
        "name": directory,
        "fileCount": file_count,
        "filteredFileCount": filtered_file_count,
        "totalBytes": total_bytes,
        "files": files,
        "offset": filter.offset,
        "limit": filter.limit,
    })])
    .to_string()
}

fn slskd_user_root_json(entries: &[BrowseEntry], query: Option<&str>) -> String {
    let filter = RecordListFilter::from_query(query);
    let grouped = group_browse_entries(entries);
    let directory_count = grouped.len();
    let total_file_count = grouped.iter().map(|(_, files)| files.len()).sum::<usize>();
    let filtered = grouped
        .into_iter()
        .filter(|(name, files)| {
            filter.q.as_deref().map_or(true, |q| {
                name.to_ascii_lowercase().contains(q)
                    || files
                        .iter()
                        .any(|entry| entry.filename.to_ascii_lowercase().contains(q))
            })
        })
        .collect::<Vec<_>>();
    let filtered_directory_count = filtered.len();
    let filtered_file_count = filtered
        .iter()
        .map(|(name, files)| {
            if let Some(q) = filter.q.as_deref() {
                if name.to_ascii_lowercase().contains(q) {
                    return files.len();
                }
                files
                    .iter()
                    .filter(|entry| entry.filename.to_ascii_lowercase().contains(q))
                    .count()
            } else {
                files.len()
            }
        })
        .sum::<usize>();
    let filtered_total_bytes = filtered
        .iter()
        .map(|(name, files)| {
            if let Some(q) = filter.q.as_deref() {
                if name.to_ascii_lowercase().contains(q) {
                    return files.iter().map(|entry| entry.size).sum::<u64>();
                }
                files
                    .iter()
                    .filter(|entry| entry.filename.to_ascii_lowercase().contains(q))
                    .map(|entry| entry.size)
                    .sum::<u64>()
            } else {
                files.iter().map(|entry| entry.size).sum::<u64>()
            }
        })
        .sum::<u64>();
    let directories = filtered
        .into_iter()
        .skip(filter.offset)
        .take(filter.limit.unwrap_or(usize::MAX))
        .map(|(name, files)| {
            let directory_matched = filter
                .q
                .as_deref()
                .is_some_and(|q| name.to_ascii_lowercase().contains(q));
            let visible_files = files
                .iter()
                .filter(|entry| {
                    if directory_matched {
                        return true;
                    }
                    filter
                        .q
                        .as_deref()
                        .map_or(true, |q| entry.filename.to_ascii_lowercase().contains(q))
                })
                .collect::<Vec<_>>();
            serde_json::json!({
                "name": name,
                "fileCount": files.len(),
                "filteredFileCount": visible_files.len(),
                "totalBytes": visible_files.iter().map(|entry| entry.size).sum::<u64>(),
                "files": visible_files.iter().map(|entry| slskd_user_file_json(entry)).collect::<Vec<_>>(),
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "directories": directories,
        "directoryCount": directory_count,
        "filteredDirectoryCount": filtered_directory_count,
        "fileCount": total_file_count,
        "filteredFileCount": filtered_file_count,
        "totalBytes": filtered_total_bytes,
        "offset": filter.offset,
        "limit": filter.limit,
        "lockedDirectories": [],
        "lockedDirectoryCount": 0,
    })
    .to_string()
}

fn slskd_empty_directory_json(name: &str) -> serde_json::Value {
    serde_json::json!({
        "name": name,
        "fullName": name,
        "attributes": "",
        "createdAt": "",
        "modifiedAt": "",
        "files": [],
        "directories": [],
    })
}

const SLSKD_STORAGE_DIRECT_LIST_DEFAULT_ENTRIES: usize = 1_024;
const SLSKD_STORAGE_DIRECT_LIST_MAX_ENTRIES: usize = 4_096;
const SLSKD_STORAGE_RECURSIVE_LIST_DEFAULT_ENTRIES: usize = 256;
const SLSKD_STORAGE_RECURSIVE_LIST_MAX_ENTRIES: usize = 1_024;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
struct StorageDirectoryListOptions {
    recursive: bool,
    limit: usize,
    offset: usize,
}

impl StorageDirectoryListOptions {
    fn from_query(query: Option<&str>) -> Self {
        let recursive = query_bool(query, "recursive").unwrap_or(false);
        let default_limit = if recursive {
            SLSKD_STORAGE_RECURSIVE_LIST_DEFAULT_ENTRIES
        } else {
            SLSKD_STORAGE_DIRECT_LIST_DEFAULT_ENTRIES
        };
        let max_limit = if recursive {
            SLSKD_STORAGE_RECURSIVE_LIST_MAX_ENTRIES
        } else {
            SLSKD_STORAGE_DIRECT_LIST_MAX_ENTRIES
        };
        let mut options = Self {
            recursive,
            limit: default_limit,
            offset: 0,
        };
        for (name, value) in query_params(query.unwrap_or_default()) {
            match name.as_str() {
                "limit" => {
                    options.limit = value
                        .parse::<usize>()
                        .ok()
                        .filter(|limit| *limit > 0)
                        .map(|limit| limit.min(max_limit))
                        .unwrap_or(default_limit);
                }
                "offset" => options.offset = value.parse::<usize>().unwrap_or(0),
                _ => {}
            }
        }
        options
    }
}

#[derive(Debug)]
struct StorageDirectoryListState {
    options: StorageDirectoryListOptions,
    seen_top_level: usize,
    emitted: usize,
    truncated: bool,
}

impl StorageDirectoryListState {
    fn new(options: StorageDirectoryListOptions) -> Self {
        Self {
            options,
            seen_top_level: 0,
            emitted: 0,
            truncated: false,
        }
    }

    fn should_emit_top_level(&mut self) -> bool {
        self.seen_top_level += 1;
        self.seen_top_level > self.options.offset
    }

    fn reserve_entry(&mut self) -> bool {
        if self.emitted >= self.options.limit {
            self.truncated = true;
            return false;
        }
        self.emitted += 1;
        true
    }
}

fn query_bool(query: Option<&str>, key: &str) -> Option<bool> {
    query_params(query.unwrap_or_default())
        .into_iter()
        .find_map(|(name, value)| (name == key).then(|| parse_bool_value(&value))?)
}

fn slskd_storage_file_json(path: &Path, root: &Path) -> serde_json::Value {
    let relative = path
        .strip_prefix(root)
        .ok()
        .and_then(|path| path.to_str())
        .unwrap_or_default()
        .replace('\\', "/");
    let name = path
        .file_name()
        .and_then(|name| name.to_str())
        .unwrap_or_default()
        .to_owned();
    let length = path.metadata().map(|metadata| metadata.len()).unwrap_or(0);
    serde_json::json!({
        "name": name,
        "fullName": relative,
        "length": length,
        "attributes": "",
        "createdAt": "",
        "modifiedAt": "",
    })
}

fn slskd_storage_directory_value(
    root: &Path,
    directory: &Path,
    state: &mut StorageDirectoryListState,
    top_level: bool,
) -> Result<serde_json::Value, String> {
    let relative = directory
        .strip_prefix(root)
        .ok()
        .and_then(|path| path.to_str())
        .unwrap_or_default()
        .replace('\\', "/");
    let name = directory
        .file_name()
        .and_then(|name| name.to_str())
        .unwrap_or_default()
        .to_owned();
    if !directory.exists() {
        let display_name = if relative.is_empty() { name } else { relative };
        return Ok(slskd_empty_directory_json(&display_name));
    }
    let metadata = directory
        .symlink_metadata()
        .map_err(|error| format!("directory metadata failed: {error}"))?;
    if metadata.file_type().is_symlink() {
        return Err("storage path must not be a symlink".to_owned());
    }
    if !metadata.is_dir() {
        return Err("storage path is not a directory".to_owned());
    }

    let mut entries = Vec::new();
    for entry in
        fs::read_dir(directory).map_err(|error| format!("directory read failed: {error}"))?
    {
        let entry = entry.map_err(|error| format!("directory entry read failed: {error}"))?;
        entries.push(entry.path());
    }
    entries.sort_by(|left, right| left.file_name().cmp(&right.file_name()));

    let mut files = Vec::new();
    let mut directories = Vec::new();
    for path in entries {
        let metadata = path
            .symlink_metadata()
            .map_err(|error| format!("directory entry metadata failed: {error}"))?;
        if metadata.file_type().is_symlink() {
            continue;
        }
        if top_level && !state.should_emit_top_level() {
            continue;
        }
        if !state.reserve_entry() {
            break;
        }
        if metadata.is_file() {
            files.push(slskd_storage_file_json(&path, root));
        } else if metadata.is_dir() {
            if state.options.recursive {
                directories.push(slskd_storage_directory_value(root, &path, state, false)?);
            } else {
                let child_relative = path
                    .strip_prefix(root)
                    .ok()
                    .and_then(|path| path.to_str())
                    .unwrap_or_default()
                    .replace('\\', "/");
                directories.push(slskd_empty_directory_json(&child_relative));
            }
        }
    }
    files.sort_by(|left, right| left["fullName"].as_str().cmp(&right["fullName"].as_str()));
    directories.sort_by(|left, right| left["fullName"].as_str().cmp(&right["fullName"].as_str()));
    Ok(serde_json::json!({
        "name": name,
        "fullName": relative,
        "attributes": "",
        "createdAt": "",
        "modifiedAt": "",
        "files": files,
        "directories": directories,
        "offset": if top_level { state.options.offset } else { 0 },
        "limit": state.options.limit,
        "entryCount": state.emitted,
        "truncated": state.truncated,
    }))
}

fn slskd_storage_directory_json(
    root: &Path,
    encoded_name: Option<&str>,
    options: StorageDirectoryListOptions,
) -> Result<String, String> {
    fs::create_dir_all(root).map_err(|error| format!("storage root create failed: {error}"))?;
    let path = if let Some(encoded_name) = encoded_name {
        let decoded = decode_slskd_base64_path_segment(encoded_name)?;
        scoped_relative_storage_path(root, &decoded)?
    } else {
        root.to_path_buf()
    };
    let canonical_root = root
        .canonicalize()
        .map_err(|error| format!("storage root canonicalize failed: {error}"))?;
    let canonical_parent = if path == root {
        canonical_root.clone()
    } else if path.exists() {
        path.parent()
            .unwrap_or(root)
            .canonicalize()
            .map_err(|error| format!("storage parent canonicalize failed: {error}"))?
    } else {
        path.parent()
            .unwrap_or(root)
            .canonicalize()
            .map_err(|error| format!("storage parent canonicalize failed: {error}"))?
    };
    if !canonical_parent.starts_with(&canonical_root) {
        return Err("path escapes the storage root".to_owned());
    }
    let mut state = StorageDirectoryListState::new(options);
    slskd_storage_directory_value(root, &path, &mut state, true).map(|value| value.to_string())
}

fn slskd_transfer_summary_report(query: Option<&str>, transfers: &TransferQueue) -> String {
    let direction = slskd_transfer_query_direction(query);
    let username = slskd_transfer_query_username(query);
    let entries = transfers
        .entries
        .iter()
        .filter(|entry| slskd_transfer_matches_query(entry, direction, username.as_deref()))
        .collect::<Vec<_>>();
    let downloads = entries.iter().filter(|entry| entry.direction == 0).count();
    let uploads = entries.iter().filter(|entry| entry.direction == 1).count();
    let total_bytes = entries
        .iter()
        .map(|entry| entry.bytes_transferred)
        .sum::<u64>();
    let mut by_state = BTreeMap::new();
    for entry in &entries {
        let state = slskd_transfer_state(&entry.status).to_owned();
        let count = by_state.entry(state).or_insert(0usize);
        *count += 1;
    }
    let by_state = by_state
        .into_iter()
        .map(|(state, count)| (state, serde_json::json!({ "count": count })))
        .collect::<BTreeMap<_, _>>();
    serde_json::json!({
        "count": entries.len(),
        "downloads": downloads,
        "uploads": uploads,
        "totalBytes": total_bytes,
        "averageSpeed": 0.0,
        "byDirection": {
            "Download": { "count": downloads },
            "Upload": { "count": uploads },
        },
        "byState": by_state,
    })
    .to_string()
}

fn slskd_transfer_query_direction(query: Option<&str>) -> Option<u32> {
    query_params(query.unwrap_or_default())
        .into_iter()
        .find_map(|(name, value)| {
            (name == "direction").then(|| match value.to_ascii_lowercase().as_str() {
                "download" | "0" => Some(0),
                "upload" | "1" => Some(1),
                _ => None,
            })?
        })
}

fn slskd_transfer_query_username(query: Option<&str>) -> Option<String> {
    query_params(query.unwrap_or_default())
        .into_iter()
        .find_map(|(name, value)| (name == "username" && !value.is_empty()).then_some(value))
}

fn slskd_transfer_query_limit_offset(query: Option<&str>) -> (usize, usize) {
    let mut limit = DEFAULT_LIST_LIMIT;
    let mut offset = 0usize;
    for (name, value) in query_params(query.unwrap_or_default()) {
        match name.as_str() {
            "limit" => limit = parse_list_limit(&value),
            "offset" => offset = value.parse::<usize>().unwrap_or(0),
            _ => {}
        }
    }
    (limit, offset)
}

fn slskd_transfer_query_value(query: Option<&str>, key: &str) -> Option<String> {
    query_params(query.unwrap_or_default())
        .into_iter()
        .find_map(|(name, value)| {
            (name.eq_ignore_ascii_case(key) && !value.is_empty()).then_some(value)
        })
}

fn slskd_transfer_matches_query(
    entry: &TransferEntry,
    direction: Option<u32>,
    username: Option<&str>,
) -> bool {
    direction.map_or(true, |direction| entry.direction == direction)
        && username.map_or(true, |username| {
            entry.peer_username.as_deref() == Some(username)
        })
}

fn slskd_transfer_speeds_json(transfers: &TransferQueue) -> String {
    let active_downloads = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0 && is_active_transfer_status(&entry.status))
        .count();
    let active_uploads = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 1 && is_active_transfer_status(&entry.status))
        .count();
    let download_bytes = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .map(|entry| entry.bytes_transferred)
        .sum::<u64>();
    let upload_bytes = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 1)
        .map(|entry| entry.bytes_transferred)
        .sum::<u64>();
    serde_json::json!({
        "active_transfers": active_downloads + active_uploads,
        "activeDownloads": active_downloads,
        "activeUploads": active_uploads,
        "total_bytes_transferred": download_bytes.saturating_add(upload_bytes),
        "downloadBytesTransferred": download_bytes,
        "uploadBytesTransferred": upload_bytes,
        "downloadSpeed": 0.0,
        "uploadSpeed": 0.0,
        "average_speed": 0.0,
    })
    .to_string()
}

fn slskd_download_stats_json(transfers: &TransferQueue) -> String {
    let downloads = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .collect::<Vec<_>>();
    let queued = downloads
        .iter()
        .filter(|entry| entry.status == "queued")
        .count();
    let active = downloads
        .iter()
        .filter(|entry| is_active_transfer_status(&entry.status))
        .count();
    let completed = downloads
        .iter()
        .filter(|entry| matches!(entry.status.as_str(), "succeeded" | "completed"))
        .count();
    let failed = downloads
        .iter()
        .filter(|entry| matches!(entry.status.as_str(), "failed" | "rejected"))
        .count();
    let cancelled = downloads
        .iter()
        .filter(|entry| entry.status == "cancelled")
        .count();
    let total_size = downloads
        .iter()
        .map(|entry| entry.size.unwrap_or(0))
        .sum::<u64>();
    let bytes_transferred = downloads
        .iter()
        .map(|entry| entry.bytes_transferred)
        .sum::<u64>();
    serde_json::json!({
        "total_downloads": downloads.len(),
        "totalDownloads": downloads.len(),
        "queued": queued,
        "active": active,
        "completed": completed,
        "failed": failed,
        "cancelled": cancelled,
        "total_size": total_size,
        "totalSize": total_size,
        "bytes_transferred": bytes_transferred,
        "bytesTransferred": bytes_transferred,
    })
    .to_string()
}

fn slskd_accelerated_downloads_json(query: Option<&str>, transfers: &TransferQueue) -> String {
    let username = slskd_transfer_query_username(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let mut candidates = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .filter(|entry| slskd_transfer_matches_query(entry, None, username.as_deref()))
        .filter(|entry| {
            matches!(
                entry.status.as_str(),
                "queued" | "peer_lookup" | "peer_negotiating" | "indirect_pending" | "in_progress"
            )
        })
        .collect::<Vec<_>>();
    candidates.sort_by(|left, right| {
        left.requested_at
            .cmp(&right.requested_at)
            .then_with(|| left.id.cmp(&right.id))
    });
    let count = candidates.len();
    let accelerated = candidates
        .into_iter()
        .skip(offset)
        .take(limit)
        .map(|entry| {
            serde_json::json!({
                "id": entry.id.to_string(),
                "username": entry.peer_username.as_deref().unwrap_or_default(),
                "filename": entry.filename,
                "state": slskd_transfer_state(&entry.status),
                "bytesTransferred": entry.bytes_transferred,
                "size": entry.size.unwrap_or(0),
                "position": transfers.slskd_transfer_position(0, entry.peer_username.as_deref().unwrap_or_default(), entry.id),
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "enabled": false,
        "available": count > 0,
        "accelerated": accelerated,
        "count": count,
        "offset": offset,
        "limit": limit,
    })
    .to_string()
}

fn slskd_stuck_downloads_json(query: Option<&str>, transfers: &TransferQueue) -> String {
    let username = slskd_transfer_query_username(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let mut entries = transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .filter(|entry| slskd_transfer_matches_query(entry, None, username.as_deref()))
        .filter(|entry| {
            matches!(entry.status.as_str(), "failed" | "rejected")
                || (is_active_transfer_status(&entry.status) && entry.bytes_transferred == 0)
        })
        .collect::<Vec<_>>();
    entries.sort_by(|left, right| {
        right
            .updated_at
            .cmp(&left.updated_at)
            .then_with(|| left.filename.cmp(&right.filename))
            .then_with(|| left.id.cmp(&right.id))
    });
    let count = entries.len();
    let stuck = entries
        .into_iter()
        .skip(offset)
        .take(limit)
        .map(|entry| {
            serde_json::json!({
                "id": entry.id.to_string(),
                "username": entry.peer_username.as_deref().unwrap_or_default(),
                "filename": entry.filename,
                "state": slskd_transfer_state(&entry.status),
                "bytesTransferred": entry.bytes_transferred,
                "size": entry.size.unwrap_or(0),
                "reason": entry.reason.as_deref().unwrap_or(""),
                "updatedAt": entry.updated_at.to_string(),
            })
        })
        .collect::<Vec<_>>();
    serde_json::json!({
        "stuck": stuck,
        "count": count,
        "offset": offset,
        "limit": limit,
    })
    .to_string()
}

fn slskd_download_user_stats_json(query: Option<&str>, transfers: &TransferQueue) -> String {
    let username_filter = slskd_transfer_query_username(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let mut grouped: BTreeMap<String, (usize, usize, usize, usize, u64, u64)> = BTreeMap::new();
    for entry in transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .filter(|entry| slskd_transfer_matches_query(entry, None, username_filter.as_deref()))
    {
        let stats = grouped
            .entry(entry.peer_username.clone().unwrap_or_default())
            .or_insert((0, 0, 0, 0, 0, 0));
        stats.0 += 1;
        if entry.status == "queued" {
            stats.1 += 1;
        }
        if is_active_transfer_status(&entry.status) {
            stats.2 += 1;
        }
        if matches!(
            entry.status.as_str(),
            "succeeded" | "completed" | "cancelled" | "failed" | "rejected"
        ) {
            stats.3 += 1;
        }
        stats.4 = stats.4.saturating_add(entry.bytes_transferred);
        stats.5 = stats.5.saturating_add(entry.size.unwrap_or(0));
    }
    let mut users = grouped
        .into_iter()
        .map(
            |(username, (total, queued, active, terminal, bytes_transferred, total_size))| {
                serde_json::json!({
                    "username": username,
                    "total": total,
                    "queued": queued,
                    "active": active,
                    "terminal": terminal,
                    "bytesTransferred": bytes_transferred,
                    "totalSize": total_size,
                })
            },
        )
        .collect::<Vec<_>>();
    users.sort_by(|left, right| {
        right["total"]
            .as_u64()
            .cmp(&left["total"].as_u64())
            .then_with(|| left["username"].as_str().cmp(&right["username"].as_str()))
    });
    let count = users.len();
    let users = users
        .into_iter()
        .skip(offset)
        .take(limit)
        .collect::<Vec<_>>();
    serde_json::json!({
        "users": users,
        "count": count,
        "offset": offset,
        "limit": limit,
    })
    .to_string()
}

fn slskd_transfer_histogram_report(query: Option<&str>, transfers: &TransferQueue) -> String {
    let interval = query_params(query.unwrap_or_default())
        .into_iter()
        .find_map(|(name, value)| (name == "interval").then(|| value.parse::<u64>().ok())?)
        .unwrap_or(60);
    let direction = slskd_transfer_query_direction(query);
    let username = slskd_transfer_query_username(query);
    let entries = transfers
        .entries
        .iter()
        .filter(|entry| slskd_transfer_matches_query(entry, direction, username.as_deref()))
        .collect::<Vec<_>>();
    let buckets = if entries.is_empty() {
        Vec::new()
    } else {
        let downloads = entries.iter().filter(|entry| entry.direction == 0).count();
        let uploads = entries.iter().filter(|entry| entry.direction == 1).count();
        let total_bytes = entries
            .iter()
            .map(|entry| entry.bytes_transferred)
            .sum::<u64>();
        vec![serde_json::json!({
            "start": entries.iter().map(|entry| entry.requested_at).min().unwrap_or(0).to_string(),
            "end": entries.iter().map(|entry| entry.updated_at).max().unwrap_or(0).to_string(),
            "count": entries.len(),
            "downloads": downloads,
            "uploads": uploads,
            "totalBytes": total_bytes,
        })]
    };
    serde_json::json!({
        "interval": interval,
        "buckets": buckets,
    })
    .to_string()
}

fn slskd_transfer_leaderboard_report(query: Option<&str>, transfers: &TransferQueue) -> String {
    let direction = slskd_transfer_query_direction(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let sort_by = slskd_transfer_query_value(query, "sortBy")
        .unwrap_or_else(|| "Count".to_owned())
        .to_ascii_lowercase();
    let descending = slskd_transfer_query_value(query, "sortOrder")
        .map(|value| !value.eq_ignore_ascii_case("ASC"))
        .unwrap_or(true);
    let mut by_user: BTreeMap<String, (usize, u64)> = BTreeMap::new();
    for entry in transfers
        .entries
        .iter()
        .filter(|entry| slskd_transfer_matches_query(entry, direction, None))
    {
        let username = entry.peer_username.clone().unwrap_or_default();
        let bytes = entry.size.unwrap_or(entry.bytes_transferred);
        let summary = by_user.entry(username).or_insert((0, 0));
        summary.0 += 1;
        summary.1 = summary.1.saturating_add(bytes);
    }
    let mut rows = by_user
        .into_iter()
        .map(|(username, (count, total_bytes))| {
            serde_json::json!({
                "username": username,
                "count": count,
                "totalBytes": total_bytes,
                "averageSpeed": 0.0,
            })
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| {
        let ordering = match sort_by.as_str() {
            "totalbytes" => left["totalBytes"]
                .as_u64()
                .cmp(&right["totalBytes"].as_u64()),
            "averagespeed" => left["averageSpeed"]
                .as_f64()
                .partial_cmp(&right["averageSpeed"].as_f64())
                .unwrap_or(std::cmp::Ordering::Equal),
            _ => left["count"].as_u64().cmp(&right["count"].as_u64()),
        };
        let ordering = if descending {
            ordering.reverse()
        } else {
            ordering
        };
        ordering.then_with(|| left["username"].as_str().cmp(&right["username"].as_str()))
    });
    serde_json::Value::Array(rows.into_iter().skip(offset).take(limit).collect()).to_string()
}

fn slskd_transfer_exceptions_report(query: Option<&str>, transfers: &TransferQueue) -> String {
    let direction = slskd_transfer_query_direction(query);
    let username = slskd_transfer_query_username(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let descending = slskd_transfer_query_value(query, "sortOrder")
        .map(|value| !value.eq_ignore_ascii_case("ASC"))
        .unwrap_or(true);
    let mut entries = transfers
        .entries
        .iter()
        .filter(|entry| slskd_transfer_matches_query(entry, direction, username.as_deref()))
        .filter(|entry| {
            matches!(
                slskd_transfer_state(&entry.status),
                "Cancelled" | "Failed" | "Rejected"
            )
        })
        .collect::<Vec<_>>();
    entries.sort_by(|left, right| {
        let ordering = left.requested_at.cmp(&right.requested_at);
        let ordering = if descending {
            ordering.reverse()
        } else {
            ordering
        };
        ordering
            .then_with(|| left.filename.cmp(&right.filename))
            .then_with(|| left.id.cmp(&right.id))
    });
    let rows = entries
        .into_iter()
        .skip(offset)
        .take(limit)
        .map(|entry| {
            serde_json::json!({
                "username": entry.peer_username.as_deref().unwrap_or_default(),
                "direction": if entry.direction == 0 { "Download" } else { "Upload" },
                "filename": entry.filename,
                "state": slskd_transfer_state(&entry.status),
                "exception": entry.reason.as_deref().unwrap_or(slskd_transfer_state(&entry.status)),
                "requestedAt": entry.requested_at.to_string(),
            })
        })
        .collect::<Vec<_>>();
    serde_json::Value::Array(rows).to_string()
}

fn slskd_transfer_exceptions_pareto_report(
    query: Option<&str>,
    transfers: &TransferQueue,
) -> String {
    let direction = slskd_transfer_query_direction(query);
    let username = slskd_transfer_query_username(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let mut grouped: BTreeMap<String, (usize, BTreeMap<String, ()>)> = BTreeMap::new();
    for entry in transfers
        .entries
        .iter()
        .filter(|entry| slskd_transfer_matches_query(entry, direction, username.as_deref()))
        .filter(|entry| {
            matches!(
                slskd_transfer_state(&entry.status),
                "Cancelled" | "Failed" | "Rejected"
            )
        })
    {
        let exception = entry
            .reason
            .clone()
            .unwrap_or_else(|| slskd_transfer_state(&entry.status).to_owned());
        let group = grouped.entry(exception).or_insert((0, BTreeMap::new()));
        group.0 += 1;
        group
            .1
            .insert(entry.peer_username.clone().unwrap_or_default(), ());
    }
    let mut rows = grouped
        .into_iter()
        .map(|(exception, (count, users))| {
            serde_json::json!({
                "exception": exception,
                "count": count,
                "distinctUsers": users.len(),
            })
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| {
        right["count"]
            .as_u64()
            .cmp(&left["count"].as_u64())
            .then_with(|| left["exception"].as_str().cmp(&right["exception"].as_str()))
    });
    serde_json::Value::Array(rows.into_iter().skip(offset).take(limit).collect()).to_string()
}

fn slskd_transfer_directories_report(query: Option<&str>, transfers: &TransferQueue) -> String {
    let username = slskd_transfer_query_username(query);
    let (limit, offset) = slskd_transfer_query_limit_offset(query);
    let mut grouped: BTreeMap<String, (usize, u64, BTreeMap<String, ()>)> = BTreeMap::new();
    for entry in transfers
        .entries
        .iter()
        .filter(|entry| entry.direction == 0)
        .filter(|entry| slskd_transfer_matches_query(entry, None, username.as_deref()))
    {
        let directory = Path::new(&entry.filename)
            .parent()
            .and_then(|path| path.to_str())
            .filter(|path| !path.is_empty())
            .unwrap_or("")
            .replace('\\', "/");
        let bytes = entry.size.unwrap_or(entry.bytes_transferred);
        let group = grouped.entry(directory).or_insert((0, 0, BTreeMap::new()));
        group.0 += 1;
        group.1 = group.1.saturating_add(bytes);
        group
            .2
            .insert(entry.peer_username.clone().unwrap_or_default(), ());
    }
    let mut rows = grouped
        .into_iter()
        .map(|(directory, (count, total_bytes, users))| {
            serde_json::json!({
                "path": directory,
                "directory": directory,
                "count": count,
                "totalBytes": total_bytes,
                "distinctUsers": users.len(),
            })
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| {
        right["count"]
            .as_u64()
            .cmp(&left["count"].as_u64())
            .then_with(|| left["path"].as_str().cmp(&right["path"].as_str()))
    });
    serde_json::Value::Array(rows.into_iter().skip(offset).take(limit).collect()).to_string()
}

fn slskd_user_transfer_report(username: &str, transfers: &TransferQueue) -> String {
    let entries = transfers
        .entries
        .iter()
        .filter(|entry| entry.peer_username.as_deref() == Some(username))
        .map(TransferEntry::slskd_file_json)
        .collect::<Vec<_>>();
    serde_json::json!({
        "username": username,
        "count": entries.len(),
        "transfers": entries,
    })
    .to_string()
}

async fn serve(once: bool) -> Result<(), String> {
    let config = AppConfig::from_env()?;
    std::fs::create_dir_all(&config.state_dir).map_err(|error| {
        format!(
            "failed to create state dir {}: {error}",
            config.state_dir.display()
        )
    })?;
    let address = config.http_bind;
    let scanned_share_index = build_share_index(&config);
    let (session_commands, session_receiver) = mpsc::channel(16);
    let (event_tx, _) = broadcast::channel(EVENT_HISTORY_LIMIT);
    let db = if config.persistence_enabled {
        let db_path = config.state_dir.join("slskr.db");
        Some(
            crate::persistence::DatabaseManager::new(db_path.to_str().unwrap_or("slskr.db"))
                .await
                .map_err(|error| format!("failed to open persistence database: {error}"))?,
        )
    } else {
        None
    };
    let share_index = if let Some(db) = db.as_ref() {
        let records = db
            .list_share_files(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted share index: {error}"))?;
        if records.is_empty() {
            let records = persisted_share_file_records(&scanned_share_index);
            db.replace_share_files(&records)
                .await
                .map_err(|error| format!("failed to persist share index: {error}"))?;
            scanned_share_index
        } else {
            ShareIndexSnapshot::from_persisted(&config, records)
        }
    } else {
        scanned_share_index
    };
    let search_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_searches(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted searches: {error}"))?;
        let result_records = db
            .list_search_results(None, EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted search results: {error}"))?;
        SearchStore::from_persisted_with_results(records, result_records)
    } else {
        SearchStore::new()
    };
    let message_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_messages(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted messages: {error}"))?;
        MessageStore::from_persisted(records)
    } else {
        MessageStore::new()
    };
    let user_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_user_projections(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted users: {error}"))?;
        UserStore::from_persisted(records)
    } else {
        UserStore::new()
    };
    let room_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_subscribed_rooms()
            .await
            .map_err(|error| format!("failed to load persisted rooms: {error}"))?;
        RoomStore::from_persisted(records)
    } else {
        RoomStore::new()
    };
    let browse_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_browse_records(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted browse records: {error}"))?;
        BrowseStore::from_persisted(records)
    } else {
        BrowseStore::new()
    };
    let user_note_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_user_notes(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted user notes: {error}"))?;
        UserNoteStore::from_persisted(records)
    } else {
        UserNoteStore::new()
    };
    let interest_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_interests(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted interests: {error}"))?;
        InterestStore::from_persisted(records)
    } else {
        InterestStore::new()
    };
    let security_state = if let Some(db) = db.as_ref() {
        let records = db
            .list_security_bans()
            .await
            .map_err(|error| format!("failed to load persisted security bans: {error}"))?;
        SecurityState::from_persisted(records)
    } else {
        SecurityState::new()
    };
    let wishlist_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_wishlist_items(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted wishlist items: {error}"))?;
        WishlistStore::from_persisted(records)
    } else {
        WishlistStore::new()
    };
    let contact_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_contacts(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted contacts: {error}"))?;
        ContactStore::from_persisted(records)
    } else {
        ContactStore::new()
    };
    let share_grant_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_share_grants(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted share grants: {error}"))?;
        ShareGrantStore::from_persisted(records)
    } else {
        ShareGrantStore::new()
    };
    let share_group_store = if let Some(db) = db.as_ref() {
        let groups = db
            .list_share_groups(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted share groups: {error}"))?;
        let members = db
            .list_share_group_members(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted share group members: {error}"))?;
        ShareGroupStore::from_persisted(groups, members)
    } else {
        ShareGroupStore::new()
    };
    let collection_store = if let Some(db) = db.as_ref() {
        let collections = db
            .list_collections(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted collections: {error}"))?;
        let items = db
            .list_collection_items(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted collection items: {error}"))?;
        CollectionStore::from_persisted(collections, items)
    } else {
        CollectionStore::new()
    };
    let library_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_library_items(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted library items: {error}"))?;
        LibraryStore::from_persisted(records)
    } else {
        LibraryStore::new()
    };
    let destination_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_destinations(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted destinations: {error}"))?;
        DestinationStore::from_persisted(records)
    } else {
        DestinationStore::new()
    };
    let now_playing_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_now_playing(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted now-playing records: {error}"))?;
        NowPlayingStore::from_persisted(records)
    } else {
        NowPlayingStore::new()
    };
    let event_store = if let Some(db) = db.as_ref() {
        let records = db
            .list_events(EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted events: {error}"))?;
        EventStore::from_persisted(records, EVENT_HISTORY_LIMIT)
    } else {
        EventStore::new(EVENT_HISTORY_LIMIT)
    };
    let runtime_compat_record = if let Some(db) = db.as_ref() {
        db.get_runtime_compat_state().await.map_err(|error| {
            format!("failed to load persisted runtime compatibility state: {error}")
        })?
    } else {
        None
    };
    let oauth_state_store = if let Some(db) = db.as_ref() {
        let now = i64::try_from(unix_timestamp()).unwrap_or(i64::MAX);
        let _ = db.delete_expired_oauth_states(now).await;
        let records = db
            .list_oauth_states(now, EVENT_HISTORY_LIMIT as i32, 0)
            .await
            .map_err(|error| format!("failed to load persisted OAuth states: {error}"))?;
        OAuthStateStore::from_persisted(records)
    } else {
        OAuthStateStore::default()
    };
    let webhook_manager = if let Some(db) = db.as_ref() {
        let records = db
            .list_webhooks()
            .await
            .map_err(|error| format!("failed to load persisted webhooks: {error}"))?;
        webhooks::WebhookManager::from_webhooks(
            records
                .into_iter()
                .filter_map(webhook_from_persisted)
                .collect(),
        )
    } else {
        webhooks::WebhookManager::new()
    };
    let relay_state = runtime_compat_record
        .as_ref()
        .map(RelayState::from_persisted)
        .unwrap_or_else(RelayState::new);
    let runtime_compat_state = runtime_compat_record
        .as_ref()
        .map(RuntimeCompatState::from_persisted)
        .unwrap_or_else(RuntimeCompatState::new);

    let rate_limiter = rate_limit::RateLimiter::new(rate_limit::RateLimitConfig {
        max_requests_anonymous: config.api_rate_limit_anonymous,
        max_requests_authenticated: config.api_rate_limit_authenticated,
        window_seconds: 60,
        enabled: true,
    });

    let state = Arc::new(AppState {
        log_level: RwLock::new(
            logging::LogConfig::parse_level(&config.log_level).unwrap_or(logging::LogLevel::Info),
        ),
        runtime_credentials: RwLock::new(None),
        session: RwLock::new(SessionSnapshot::disconnected(&config)),
        listeners: RwLock::new(ListenerSnapshot::new(&config)),
        shares: RwLock::new(share_index),
        searches: RwLock::new(search_store),
        users: RwLock::new(user_store),
        mesh: RwLock::new(MeshState::new()),
        browse: RwLock::new(browse_store),
        messages: RwLock::new(message_store),
        rooms: RwLock::new(room_store),
        transfers: RwLock::new(TransferQueue::new(&config)),
        events: RwLock::new(event_store),
        event_tx,
        webhooks: RwLock::new(webhook_manager),
        webhook_deliveries: Arc::new(Semaphore::new(MAX_WEBHOOK_DELIVERY_TASKS)),
        collections: RwLock::new(collection_store),
        wishlist: RwLock::new(wishlist_store),
        contacts: RwLock::new(contact_store),
        sharegroups: RwLock::new(share_group_store),
        user_notes: RwLock::new(user_note_store),
        interests: RwLock::new(interest_store),
        now_playing: RwLock::new(now_playing_store),
        relay: RwLock::new(relay_state),
        runtime: RwLock::new(runtime_compat_state),
        security: RwLock::new(security_state),
        share_grants: RwLock::new(share_grant_store),
        library: RwLock::new(library_store),
        destinations: RwLock::new(destination_store),
        db,
        config,
        session_commands,
        rate_limiter,
        oauth_states: RwLock::new(oauth_state_store),
        stream_tickets: RwLock::new(PreviewStreamTicketStore::default()),
    });
    match credential_store::load(&state.config) {
        Ok(Some(stored)) => {
            let username = redact_username(&stored.credentials.username);
            {
                let mut runtime_credentials = state.runtime_credentials.write().await;
                *runtime_credentials = Some(stored.credentials);
            }
            record_daemon_log(
                &state,
                logging::LogLevel::Info,
                "session",
                format!(
                    "loaded Soulseek credentials for {} from {} credential store",
                    username, stored.source
                ),
            )
            .await;
        }
        Ok(None) => {}
        Err(error) => {
            record_daemon_log(
                &state,
                logging::LogLevel::Warn,
                "session",
                format!("could not load stored Soulseek credentials: {error}"),
            )
            .await;
        }
    }
    spawn_session_manager(Arc::clone(&state), session_receiver);
    spawn_configured_listeners(Arc::clone(&state));
    spawn_rate_limit_cleanup(Arc::clone(&state));
    record_daemon_log(
        &state,
        logging::LogLevel::Info,
        "daemon",
        format!(
            "slskr {} listening on {} with log level {}",
            APP_VERSION,
            address,
            logging::LogConfig::level_name(*state.log_level.read().await)
        ),
    )
    .await;

    if state.config.auto_connect {
        let credential_source = if state.runtime_credentials.read().await.is_some() {
            "stored"
        } else if state.config.credentials().is_some() {
            "config"
        } else {
            state.config.credential_store.as_str()
        };
        record_daemon_log(
            &state,
            logging::LogLevel::Info,
            "session",
            format!(
                "auto-connect enabled; queuing Soulseek connect using {credential_source} credentials"
            ),
        )
        .await;
        send_session_command(&state, SessionCommand::Connect).await?;
    } else {
        record_daemon_log(
            &state,
            logging::LogLevel::Info,
            "session",
            "auto-connect disabled; Soulseek connection will wait for an explicit connect request",
        )
        .await;
    }

    let listener = TcpListener::bind(address)
        .await
        .map_err(|error| format!("failed to bind {address}: {error}"))?;
    println!("slskr listening on http://{address}");
    if auth_disabled_on_non_loopback(&state.config) {
        eprintln!(
            "WARNING: HTTP API authentication is disabled on non-loopback bind {}; remote clients can control slskr",
            state.config.http_bind
        );
    } else if !state.config.auth_required {
        eprintln!(
            "WARNING: HTTP API authentication is disabled on {}; local processes can control slskr",
            state.config.http_bind
        );
    }
    let http_connections = Arc::new(Semaphore::new(256));

    loop {
        let (stream, _) = listener
            .accept()
            .await
            .map_err(|error| format!("accept failed: {error}"))?;
        let Ok(permit) = Arc::clone(&http_connections).try_acquire_owned() else {
            drop(stream);
            continue;
        };
        let state = Arc::clone(&state);
        tokio::spawn(async move {
            let _permit = permit;
            if let Err(error) = handle_http_connection(stream, state).await {
                eprintln!("http request failed: {error}");
            }
        });

        if once {
            break;
        }
    }

    Ok(())
}

fn spawn_session_manager(state: Arc<AppState>, mut receiver: mpsc::Receiver<SessionCommand>) {
    tokio::spawn(async move {
        let mut session = None;
        let mut next_ping = Instant::now() + state.config.ping_interval;
        let mut wishlist_scheduler = WishlistSearchScheduler::new(
            Vec::<String>::new(),
            WishlistSearchSchedulerOptions::new(Duration::from_secs(30), None)
                .expect("valid wishlist scheduler options"),
        )
        .expect("valid empty wishlist scheduler");
        let mut next_wishlist_search = Instant::now() + wishlist_scheduler.interval();
        let mut reconnect_requested = false;

        loop {
            while let Ok(command) = receiver.try_recv() {
                handle_session_command(
                    &state,
                    command,
                    &mut session,
                    &mut next_ping,
                    &mut reconnect_requested,
                )
                .await;
            }

            if reconnect_requested && session.is_none() {
                time::sleep(state.config.reconnect_delay).await;
                let connected = connect_session(&state, &mut session, &mut next_ping).await;
                reconnect_requested = !connected && state.config.reconnect;
                continue;
            }

            if let Some(active_session) = session.as_mut() {
                if matches!(
                    time::timeout(Duration::from_millis(250), active_session.readable()).await,
                    Ok(Ok(()))
                ) {
                    match time::timeout(Duration::from_secs(1), active_session.receive()).await {
                        Ok(Ok(message)) => {
                            if wishlist_scheduler.apply_server_message(&message) {
                                next_wishlist_search =
                                    Instant::now() + wishlist_scheduler.interval();
                            }
                            project_server_message(&state, active_session, &message).await;
                            update_session(&state, |snapshot| {
                                snapshot.state = "connected";
                                snapshot.server_messages_seen += 1;
                                snapshot.last_server_message =
                                    Some(server_message_name(&message).to_string());
                            })
                            .await;
                        }
                        Ok(Err(error)) => {
                            eprintln!("server receive failed: {error}");
                            session = None;
                            update_session(&state, |snapshot| {
                                snapshot.state = "error";
                                snapshot.last_error =
                                    Some(format!("server receive failed: {error}"));
                                snapshot.supporter = None;
                                snapshot.connected_at = None;
                            })
                            .await;
                            reconnect_requested = state.config.reconnect;
                        }
                        Err(_) => {}
                    }
                }

                if session.is_some() && Instant::now() >= next_ping {
                    send_session_ping(&state, &mut session, &mut next_ping).await;
                    reconnect_requested = session.is_none() && state.config.reconnect;
                }

                if session.is_some() && Instant::now() >= next_wishlist_search {
                    send_due_wishlist_search(
                        &state,
                        &mut session,
                        &mut wishlist_scheduler,
                        &mut next_wishlist_search,
                    )
                    .await;
                    reconnect_requested = session.is_none() && state.config.reconnect;
                }
            } else if let Some(command) = receiver.recv().await {
                handle_session_command(
                    &state,
                    command,
                    &mut session,
                    &mut next_ping,
                    &mut reconnect_requested,
                )
                .await;
            } else {
                break;
            }
        }
    });
}

fn spawn_rate_limit_cleanup(state: Arc<AppState>) {
    tokio::spawn(async move {
        let mut interval = time::interval(Duration::from_secs(60));
        loop {
            interval.tick().await;
            state.rate_limiter.cleanup().await;
        }
    });
}

fn spawn_configured_listeners(state: Arc<AppState>) {
    if let Some(bind) = state.config.listener_bind.clone() {
        tokio::spawn(run_listener(Arc::clone(&state), bind, false));
    }
    if let Some(bind) = state.config.obfuscated_listener_bind.clone() {
        tokio::spawn(run_listener(Arc::clone(&state), bind, true));
    }
}

async fn run_listener(state: Arc<AppState>, bind: String, obfuscated: bool) {
    let listener = match Listener::bind(bind.as_str()).await {
        Ok(listener) => listener,
        Err(error) => {
            update_listeners(&state, |snapshot| {
                snapshot.errors += 1;
                snapshot.last_error = Some(format!(
                    "{} listener bind failed: {error}",
                    if obfuscated { "obfuscated" } else { "regular" }
                ));
            })
            .await;
            return;
        }
    };

    let local_addr = listener.local_addr().ok().map(|addr| addr.to_string());
    update_listeners(&state, |snapshot| {
        if obfuscated {
            snapshot.obfuscated_local_addr = local_addr;
        } else {
            snapshot.regular_local_addr = local_addr;
        }
        snapshot.last_error = None;
    })
    .await;

    loop {
        let accepted = if obfuscated {
            listener.accept_obfuscated().await
        } else {
            listener.accept().await
        };
        match accepted {
            Ok((incoming, remote_addr)) => {
                let event = format!(
                    "{} from {}",
                    incoming_connection_name(&incoming),
                    scrub_socket_addr(remote_addr)
                );
                update_listeners(&state, |snapshot| {
                    if obfuscated {
                        snapshot.obfuscated_accepts += 1;
                    } else {
                        snapshot.regular_accepts += 1;
                    }
                    bump_incoming_counter(snapshot, &incoming);
                    snapshot.last_event = Some(event);
                    snapshot.last_error = None;
                })
                .await;
                tokio::spawn(handle_owned_incoming(Arc::clone(&state), incoming));
            }
            Err(error) => {
                update_listeners(&state, |snapshot| {
                    snapshot.errors += 1;
                    snapshot.last_error = Some(format!(
                        "{} listener accept failed: {error}",
                        if obfuscated { "obfuscated" } else { "regular" }
                    ));
                })
                .await;
            }
        }
    }
}

async fn handle_session_command(
    state: &AppState,
    command: SessionCommand,
    session: &mut Option<ServerSession<TcpStream>>,
    next_ping: &mut Instant,
    reconnect_requested: &mut bool,
) {
    match command {
        SessionCommand::Connect => {
            *reconnect_requested = false;
            if session.is_none() {
                let _connected = connect_session(state, session, next_ping).await;
            } else {
                update_session(state, |snapshot| {
                    snapshot.state = "connected";
                    snapshot.last_error = None;
                })
                .await;
            }
        }
        SessionCommand::Disconnect => {
            *session = None;
            *reconnect_requested = false;
            update_session(state, |snapshot| {
                snapshot.state = "disconnected";
                snapshot.supporter = None;
                snapshot.last_error = None;
                snapshot.connected_at = None;
            })
            .await;
        }
        SessionCommand::Ping => {
            if session.is_some() {
                send_session_ping(state, session, next_ping).await;
            } else {
                update_session(state, |snapshot| {
                    snapshot.state = "disconnected";
                    snapshot.last_error = Some("cannot ping while disconnected".to_owned());
                })
                .await;
            }
        }
        SessionCommand::CheckPrivileges => {
            send_active_server_message(
                state,
                session,
                ServerMessage::CheckPrivilegesRequest,
                "check privileges",
            )
            .await;
        }
        SessionCommand::Search {
            token,
            query,
            target,
        } => {
            send_active_server_message(
                state,
                session,
                search_dispatch_message(token, query, target),
                "dispatch search",
            )
            .await;
        }
        SessionCommand::WatchUser(username) => {
            send_active_server_message(
                state,
                session,
                ServerMessage::WatchUserRequest { username },
                "watch user",
            )
            .await;
        }
        SessionCommand::UnwatchUser(username) => {
            send_active_server_message(
                state,
                session,
                ServerMessage::UnwatchUser { username },
                "unwatch user",
            )
            .await;
        }
        SessionCommand::BrowseUser(username) => {
            send_active_server_message(
                state,
                session,
                ServerMessage::GetPeerAddressRequest { username },
                "request peer address for browse",
            )
            .await;
        }
        SessionCommand::BrowseFolder { username, .. } => {
            send_active_server_message(
                state,
                session,
                ServerMessage::GetPeerAddressRequest { username },
                "request peer address for folder browse",
            )
            .await;
        }
        SessionCommand::IndirectBrowse { username, token } => {
            send_active_server_message(
                state,
                session,
                ServerMessage::ConnectToPeerRequest(ConnectToPeerRequest {
                    token,
                    username,
                    connection_type: ConnectionKind::PeerMessages.as_str().to_owned(),
                }),
                "request indirect browse",
            )
            .await;
        }
        SessionCommand::RequestUserStats(username) => {
            send_active_server_message(
                state,
                session,
                ServerMessage::GetUserStatsRequest { username },
                "request user stats",
            )
            .await;
        }
        SessionCommand::TransferPeer { id, username } => {
            send_active_server_message(
                state,
                session,
                ServerMessage::GetPeerAddressRequest { username },
                &format!("request peer address for transfer {id}"),
            )
            .await;
        }
        SessionCommand::IndirectTransfer {
            id,
            username,
            token,
        } => {
            send_active_server_message(
                state,
                session,
                ServerMessage::ConnectToPeerRequest(ConnectToPeerRequest {
                    token,
                    username,
                    connection_type: ConnectionKind::FileTransfer.as_str().to_owned(),
                }),
                &format!("request indirect file transfer {id}"),
            )
            .await;
        }
        SessionCommand::MessageUser { username, body } => {
            send_active_server_message(
                state,
                session,
                ServerMessage::MessageUserRequest {
                    username,
                    message: body,
                },
                "message user",
            )
            .await;
        }
        SessionCommand::MessageUsers { usernames, body } => {
            send_active_server_message(
                state,
                session,
                ServerMessage::MessageUsers {
                    usernames,
                    message: body,
                },
                "message users",
            )
            .await;
        }
        SessionCommand::MessageAcked { id } => {
            send_active_server_message(
                state,
                session,
                ServerMessage::MessageAcked { id },
                "ack message",
            )
            .await;
        }
        SessionCommand::RefreshRooms => {
            send_active_server_message(
                state,
                session,
                ServerMessage::RoomListRequest,
                "refresh rooms",
            )
            .await;
        }
        SessionCommand::JoinRoom(room) => {
            send_active_server_message(
                state,
                session,
                ServerMessage::JoinRoom { room },
                "join room",
            )
            .await;
        }
        SessionCommand::LeaveRoom(room) => {
            send_active_server_message(
                state,
                session,
                ServerMessage::LeaveRoom { room },
                "leave room",
            )
            .await;
        }
        SessionCommand::SayRoom { room, body } => {
            send_active_server_message(
                state,
                session,
                ServerMessage::SayChatroomRequest {
                    room,
                    message: body,
                },
                "say room",
            )
            .await;
        }
    }
}

async fn handle_owned_incoming(state: Arc<AppState>, incoming: IncomingConnection<TcpStream>) {
    let result = match incoming {
        IncomingConnection::PeerMessages(peer) => {
            handle_plain_peer_messages(&state, peer, None).await
        }
        IncomingConnection::ObfuscatedPeerMessages(peer) => {
            handle_obfuscated_peer_messages(&state, peer).await
        }
        IncomingConnection::PeerInit {
            kind: ConnectionKind::PeerMessages,
            username,
            stream,
            ..
        } => {
            handle_plain_peer_messages(&state, PeerMessageConnection::new(stream), Some(username))
                .await
        }
        IncomingConnection::FileTransfer(file) => {
            handle_inbound_file_transfer(&state, file, None).await
        }
        IncomingConnection::PeerInit {
            kind: ConnectionKind::FileTransfer,
            token,
            stream,
            ..
        } => {
            handle_inbound_file_transfer(
                &state,
                slskr_client::file_transfer::FileTransferConnection::new(stream),
                (token != 0).then_some(token),
            )
            .await
        }
        IncomingConnection::PierceFirewall { token, stream } => {
            let has_file_transfer = {
                let transfers = state.transfers.read().await;
                transfers
                    .pending_inbound_file_transfer(Some(token))
                    .is_some()
            };
            if has_file_transfer {
                handle_inbound_file_transfer(
                    &state,
                    slskr_client::file_transfer::FileTransferConnection::new(stream),
                    Some(token),
                )
                .await
            } else {
                handle_plain_peer_messages(&state, PeerMessageConnection::new(stream), None).await
            }
        }
        _ => Ok(()),
    };

    if let Err(error) = result {
        update_listeners(&state, |snapshot| {
            snapshot.errors += 1;
            snapshot.last_error = Some(error);
        })
        .await;
    }
}

async fn handle_inbound_file_transfer(
    state: &AppState,
    mut file: slskr_client::file_transfer::FileTransferConnection<TcpStream>,
    token: Option<u32>,
) -> Result<(), String> {
    let transfer = {
        let transfers = state.transfers.read().await;
        transfers.pending_inbound_file_transfer(token)
    }
    .ok_or_else(|| {
        token.map_or_else(
            || "no accepted inbound file transfer is pending".to_owned(),
            |token| format!("no accepted inbound file transfer is pending for token {token}"),
        )
    })?;

    {
        let mut transfers = state.transfers.write().await;
        transfers.update_status(transfer.id, "in_progress", None, None);
    }

    let result = if transfer.direction == 0 {
        download_file_transfer_with_connection(state, &transfer, &mut file).await
    } else {
        upload_file_transfer_with_connection(state, &transfer, &mut file).await
    };
    let (status, bytes_transferred, size, reason) = match result {
        Ok((bytes_transferred, size)) => ("succeeded", bytes_transferred, Some(size), None),
        Err(error) => (
            "failed",
            transfer.bytes_transferred,
            transfer.size,
            Some(error),
        ),
    };

    let mut transfers = state.transfers.write().await;
    transfers.update_local_execution(transfer.id, status, bytes_transferred, size, reason);
    Ok(())
}

async fn handle_plain_peer_messages(
    state: &AppState,
    mut peer: PeerMessageConnection<TcpStream>,
    peer_username: Option<String>,
) -> Result<(), String> {
    let message = receive_plain_peer_message(state, &mut peer).await?;
    if let PeerMessage::TransferRequest(request) = &message {
        if request.direction == 0 {
            if let Some(username) = peer_username.as_deref() {
                if handle_queued_upload_resume_request(state, &mut peer, username, request).await? {
                    return Ok(());
                }
                if handle_queued_download_request(state, &mut peer, username, request).await? {
                    return Ok(());
                }
            }
        } else if request.direction == 1 {
            if let Some(username) = peer_username.as_deref() {
                if handle_queued_upload_request(state, &mut peer, username, request).await? {
                    return Ok(());
                }
            }
        }
    }
    if matches!(message, PeerMessage::GetShareFileList) {
        update_listeners(state, |snapshot| {
            snapshot.share_list_requests += 1;
            snapshot.last_event = Some("share_list_request".to_owned());
        })
        .await;
        let entries = {
            let shares = state.shares.read().await;
            shares.entries.clone()
        };
        peer.send(&PeerMessage::SharedFileListResponse(
            build_shared_file_list_payload(&entries)?,
        ))
        .await
        .map_err(|error| format!("peer response send failed: {error}"))?;
        update_listeners(state, |snapshot| {
            snapshot.share_list_responses += 1;
            snapshot.last_event = Some("share_list_response".to_owned());
            snapshot.last_error = None;
        })
        .await;
        time::sleep(Duration::from_secs(2)).await;
        return Ok(());
    }
    handle_peer_message(state, message, |response| async move {
        peer.send(&response)
            .await
            .map_err(|error| format!("peer response send failed: {error}"))
    })
    .await
}

async fn handle_queued_upload_request(
    state: &AppState,
    peer: &mut PeerMessageConnection<TcpStream>,
    username: &str,
    request: &TransferRequest,
) -> Result<bool, String> {
    if !state.config.transfer_allow_inbound || !transfer_capacity_available(state, None).await {
        return Ok(false);
    }
    let accepted = {
        let mut transfers = state.transfers.write().await;
        transfers.accept_pending_remote_upload_request(
            username,
            &request.filename,
            request.token,
            request.size,
        )
    };
    let Some(accepted) = accepted else {
        return Ok(false);
    };
    peer.send(&PeerMessage::TransferResponse(TransferResponse::Allowed {
        token: request.token,
        size: accepted.size,
    }))
    .await
    .map_err(|error| format!("queued upload response send failed: {error}"))?;
    update_listeners(state, |snapshot| {
        snapshot.last_event = Some("transfer_queued_upload_accepted".to_owned());
        snapshot.last_error = None;
    })
    .await;
    Ok(true)
}

async fn handle_queued_upload_resume_request(
    state: &AppState,
    peer: &mut PeerMessageConnection<TcpStream>,
    username: &str,
    request: &TransferRequest,
) -> Result<bool, String> {
    if !state.config.transfer_allow_inbound || !transfer_capacity_available(state, None).await {
        return Ok(false);
    }
    let accepted = {
        let mut transfers = state.transfers.write().await;
        transfers.accept_pending_remote_download_request(
            username,
            &request.filename,
            request.token,
            request.size,
        )
    };
    let Some(accepted) = accepted else {
        return Ok(false);
    };
    peer.send(&PeerMessage::TransferResponse(TransferResponse::Allowed {
        token: request.token,
        size: accepted.size,
    }))
    .await
    .map_err(|error| format!("queued upload resume response send failed: {error}"))?;
    update_listeners(state, |snapshot| {
        snapshot.last_event = Some("transfer_queued_upload_resume_accepted".to_owned());
        snapshot.last_error = None;
    })
    .await;
    Ok(true)
}

async fn handle_queued_download_request(
    state: &AppState,
    peer: &mut PeerMessageConnection<TcpStream>,
    username: &str,
    request: &TransferRequest,
) -> Result<bool, String> {
    if !state.config.transfer_allow_inbound || !transfer_capacity_available(state, None).await {
        return Ok(false);
    }
    let Some(shared_file) = find_shared_local_file(state, &request.filename).await else {
        return Ok(false);
    };
    let entry = {
        let mut transfers = state.transfers.write().await;
        transfers.record_accepted_inbound_request(
            1,
            request.token,
            request.filename.clone(),
            shared_file.local_path.display().to_string(),
            shared_file.size,
        )
    };
    peer.send(&PeerMessage::TransferResponse(TransferResponse::Rejected {
        token: request.token,
        reason: "Queued".to_owned(),
    }))
    .await
    .map_err(|error| format!("queued transfer response send failed: {error}"))?;
    peer.send(&PeerMessage::TransferRequest(TransferRequest {
        direction: 1,
        token: request.token,
        filename: request.filename.clone(),
        size: Some(shared_file.size),
    }))
    .await
    .map_err(|error| format!("queued upload start request send failed: {error}"))?;
    let response = time::timeout(state.config.peer_response_timeout, peer.receive())
        .await
        .map_err(|_| "queued upload start response timed out".to_owned())?
        .map_err(|error| format!("queued upload start response failed: {error}"))?;
    match response {
        PeerMessage::TransferResponse(TransferResponse::Allowed { token, .. })
            if token == request.token =>
        {
            let Some(address) = test_user_endpoint_peer_address(state, username) else {
                let mut transfers = state.transfers.write().await;
                transfers.update_status(
                    entry.id,
                    "failed",
                    None,
                    Some("no endpoint available for queued upload transfer".to_owned()),
                );
                return Err("no endpoint available for queued upload transfer".to_owned());
            };
            execute_accepted_file_transfer(state, &address, &entry).await;
            update_listeners(state, |snapshot| {
                snapshot.last_event = Some("transfer_queued_upload_started".to_owned());
                snapshot.last_error = None;
            })
            .await;
            Ok(true)
        }
        PeerMessage::TransferResponse(TransferResponse::Rejected { token, reason })
            if token == request.token =>
        {
            let mut transfers = state.transfers.write().await;
            transfers.update_status(entry.id, "failed", None, Some(reason.clone()));
            Err(format!("queued upload rejected: {reason}"))
        }
        other => {
            let reason = format!(
                "expected queued upload TransferResponse, got {}",
                peer_message_name(&other)
            );
            let mut transfers = state.transfers.write().await;
            transfers.update_status(entry.id, "failed", None, Some(reason.clone()));
            Err(reason)
        }
    }
}

async fn handle_obfuscated_peer_messages(
    state: &AppState,
    mut peer: ObfuscatedPeerMessageConnection<TcpStream>,
) -> Result<(), String> {
    let message = receive_obfuscated_peer_message(state, &mut peer).await?;
    handle_peer_message(state, message, |response| async move {
        peer.send(&response)
            .await
            .map_err(|error| format!("obfuscated peer response send failed: {error}"))
    })
    .await
}

