            let incoming = slskr_client::listener::demux_incoming(stream)
                .await
                .expect("demux indirect");
            let slskr_client::listener::IncomingConnection::PierceFirewall { token, stream } =
                incoming
            else {
                panic!("expected pierce firewall");
            };
